INSERT INTO discriminadores (id_fluxograma, classificacao, prioridade, ordem, pergunta, explicacao) VALUES
    (105, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (105, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (105, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (105, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (105, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (105, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (105, 'MUITO URGENTE', 2, 2, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (105, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (105, 'MUITO URGENTE', 2, 4, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (105, 'MUITO URGENTE', 2, 5, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (105, 'MUITO URGENTE', 2, 6, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (105, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (105, 'URGENTE', 3, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (105, 'URGENTE', 3, 3, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (105, 'URGENTE', 3, 4, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (105, 'URGENTE', 3, 5, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (105, 'URGENTE', 3, 6, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (105, 'POUCO URGENTE', 4, 1, 'DEFORMIDADE', 'ISTO É SEMPRE SUBJETIVO. INCLUI ANGULAÇÃO OU ROTAÇÃO ANORMAL.'),
    (105, 'POUCO URGENTE', 4, 2, 'INCHAÇO', 'QUALQUER AUMENTO ANORMAL NO TAMANHO.'),
    (105, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (105, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (106, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (106, 'EMERGÊNCIA', 1, 2, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (106, 'EMERGÊNCIA', 1, 3, 'BABA-SE', 'SALIVA SAINDO PELA BOCA POR INCAPACIDADE DE ENGOLIR.'),
    (106, 'EMERGÊNCIA', 1, 4, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (106, 'EMERGÊNCIA', 1, 5, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (106, 'EMERGÊNCIA', 1, 6, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (106, 'MUITO URGENTE', 2, 1, 'EDEMA DE LÍNGUA', 'INCHAÇO NA LÍNGUA DE QUALQUER INTENSIDADE.'),
    (106, 'MUITO URGENTE', 2, 2, 'EDEMA FACIAL', 'INCHAÇO DIFUSO NA FACE GERALMENTE ENVOLVENDO OS LÁBIOS.'),
    (106, 'MUITO URGENTE', 2, 3, 'FRASES ENTRECORTADAS', 'DOENTES COM DIFICULDADE RESPIRATÓRIA TÃO GRANDE QUE NÃO CONSEGUEM NEM ARTICULAR FRASES CURTAS NUMA SÓ RESPIRAÇÃO.'),
    (106, 'MUITO URGENTE', 2, 4, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (106, 'MUITO URGENTE', 2, 5, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (106, 'MUITO URGENTE', 2, 6, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (106, 'MUITO URGENTE', 2, 7, 'HISTÓRIA ALÉRGICA IMPORTANTE', 'SENSIBILIDADE CONHECIDA COM REAÇÃO GRAVE (POR EXEMPLO: NOZES, CAMARÃO, PICADA DE ABELHA).'),
    (106, 'MUITO URGENTE', 2, 8, 'DOR OU COCEIRA INTENSA', 'COCEIRA INTOLERÁVEL.'),
    (106, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (106, 'URGENTE', 3, 2, 'ERUPÇÃO OU VESÍCULAS DISSEMINADAS', 'QUALQUER ERUPÇÃO, INCLUSIVE AS SECRETANTES OU BOLHOSAS, COBRINDO MAIS DE 10% DA SUPERFÍCIE CORPORAL.'),
    (106, 'URGENTE', 3, 3, 'DOR OU COCEIRA MODERADA', 'COCEIRA INTENSA, MAS SUPORTÁVEL.'),
    (106, 'POUCO URGENTE', 4, 1, 'INFLAMAÇÃO LOCAL', 'IMPLICA DOR, INCHAÇO E VERMELHIDÃO, RESTRITA A UMA ÁREA DEFINIDA.'),
    (106, 'POUCO URGENTE', 4, 2, 'DOR OU COCEIRA LEVE RECENTE', 'QUALQUER COCEIRA QUE OCORREU NOS ÚLTIMOS SETE DIAS.'),
    (106, 'POUCO URGENTE', 4, 3, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (107, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (107, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (107, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (107, 'EMERGÊNCIA', 1, 4, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (107, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (107, 'MUITO URGENTE', 2, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (107, 'MUITO URGENTE', 2, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (107, 'MUITO URGENTE', 2, 3, 'HISTÓRIA DE OVERDOSE OU ENVENENAMENTO', 'ESTA INFORMAÇÃO PODE VIR DE OUTROS OU PODE SER DEDUZIDA NA PRESENÇA DE CAIXAS DE REMÉDIOS VAZIAS, ENTRE OUTRAS.'),
    (107, 'MUITO URGENTE', 2, 4, 'ALTO RISCO DE AUTOAGRESSÃO', 'UMA AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE QUE TEM PASSADO IMPORTANTE DE  AUTOAGRESSÃO E ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR OU ESTÁ TENTANDO IR EMBORA PARA TAL FINALIDADE É DE ALTO RISCO.'),
    (107, 'MUITO URGENTE', 2, 5, 'ALTO RISCO DE AGREDIR OUTROS', 'A PRESENÇA DE UM RISCO POTENCIAL DE DANO A OUTROS PODE SER AVALIADO OBSERVANDO-SE A POSTURA (TENSA OU COM PUNHOS CERRADOS), O PADRÃO DE DISCURSO (ALTO, COM PALAVRAS AMEAÇADORAS) E O COMPORTAMENTO PSICOMOTOR (INQUIETUDE, ANDANDO). ALTO RISCO DEVE SER PRESUMIDO SE ARMAS E VÍTIMAS POTENCIAIS ESTÃO POR PERTO OU SE HOUVE PERDA DO AUTOCONTROLE.'),
    (107, 'URGENTE', 3, 1, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (107, 'URGENTE', 3, 2, 'HISTÓRIA DE TRAUMA CRANIOENCEFÁLICO', 'HISTÓRIA DE TRAUMA FÍSICO ENVOLVENDO A CABEÇA. GERALMENTE ISSO SERÁ RELATADO PELO PACIENTE, MAS SE ELE ESTEVE INCONSCIENTE, A HISTÓRIA DEVERÁ SER COLHIDA DE UMA TESTEMUNHA CONFIÁVEL.'),
    (107, 'URGENTE', 3, 3, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (107, 'URGENTE', 3, 4, 'HISTÓRIA PSIQUIÁTRICA IMPORTANTE', 'HISTÓRIA DE EVENTO OU DOENÇA PSIQUIÁTRICA SIGNIFICATIVA.'),
    (107, 'URGENTE', 3, 5, 'RISCO MODERADO DE AUTOAGRESSÃO', 'AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE SEM PASSADO IMPORTANTE DE AUTOAGRESSÃO, QUE NÃO ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR NEM TENTANDO IR EMBORA PARA TAL, MAS MANIFESTA DESEJO DE SE MACHUCAR, ESTÁ EM RISCO MODERADO.'),
    (107, 'URGENTE', 3, 6, 'RISCO MODERADO DE AGREDIR OUTROS', 'RISCO POTENCIAL DE DANO A OUTROS PODE SER AVALIADO OBSERVANDO-SE A POSTURA DO PACIENTE (TENSA E PUNHOS CERRADOS), O PADRÃO DE DISCURSO (ALTO, AMEAÇADOR) E COMPORTAMENTO MOTOR (INQUIETUDE, ANDANDO). RISCO MODERADO DEVE SER PRESUMIDO SE HÁ QUALQUER INDÍCIO DE POTENCIAL AGRESSÃO A ALGUÉM.'),
    (108, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (108, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (108, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (108, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (108, 'MUITO URGENTE', 2, 1, 'FRASES ENTRECORTADAS', 'DOENTES COM DIFICULDADE RESPIRATÓRIA TÃO GRANDE QUE NÃO CONSEGUEM NEM ARTICULAR FRASES CURTAS NUMA SÓ RESPIRAÇÃO.'),
    (108, 'MUITO URGENTE', 2, 2, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (108, 'MUITO URGENTE', 2, 3, 'PFE MUITO BAIXO', 'PICO DE FLUXO EXPIRATÓRIO DE 33% OU MENOS DO PREVISTO DE ACORDO COM A IDADE E SEXO DO PACIENTE (VER ESCALAS ANEXAS). ALGUNS PACIENTES CONHECEM SEU MELHOR PFE E ESTE DADO PODE SER USADO. SE A PROPORÇÃO DO VALOR MEDIDO FOR IGUAL OU INFERIOR A 33% DO PREVISTO, ESTE CRITÉRIO É PREENCHIDO.'),
    (108, 'MUITO URGENTE', 2, 4, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (108, 'MUITO URGENTE', 2, 5, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (108, 'MUITO URGENTE', 2, 6, 'HISTÓRIA RESPIRATÓRIA SIGNIFICATIVA', 'HISTÓRIA PRÉVIA DE CONDIÇÕES RESPIRATÓRIAS AMEAÇADORAS DA VIDA (POR EXEMPLO: DOENÇA PULMONAR OBSTRUTIVA CRÔNICA - DPOC, ASMA LÁBIL, USO DOMICILIAR DE O2, VENTILAÇÃO NÃO INVASIVA OU INVASIVA).'),
    (108, 'MUITO URGENTE', 2, 7, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (108, 'MUITO URGENTE', 2, 8, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (108, 'MUITO URGENTE', 2, 9, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (108, 'MUITO URGENTE', 2, 10, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (108, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (108, 'URGENTE', 3, 2, 'PFE BAIXO', 'PICO DE FLUXO EXPIRATÓRIO DE 50% OU MENOS DO PREVISTO DE ACORDO COM A IDADE E SEXO DO PACIENTE (VER ESCALAS ANEXAS). ALGUNS PACIENTES CONHECEM SEU MELHOR PFE E ESTE DADO PODE SER USADO. SE A PROPORÇÃO DO VALOR MEDIDO FOR IGUAL OU INFERIOR A 50% DO PREVISTO, ESTE CRITÉRIO É PREENCHIDO.'),
    (108, 'URGENTE', 3, 3, 'SEM MELHORA COM SUA MEDICAÇÃO HABITUAL', 'A HISTÓRIA DEVE SER CONTADA PELO PACIENTE. A AUSÊNCIA DE MELHORA DA DISPNEIA COM O BRONCODILATADOR PRESCRITO PELO MÉDICO TAMBÉM É IMPORTANTE.'),
    (108, 'URGENTE', 3, 4, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (108, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (108, 'POUCO URGENTE', 4, 1, 'CHIEIRA', 'PODE HAVER UMA SIBILÂNCIA AUDÍVEL OU SÓ UMA SENSAÇÃO DE CHIADO. OBSTRUÇÃO MAIS GRAVE DE VIAS AÉREAS PODE SER SILENCIOSA (NÃO PASSA NENHUM AR).'),
    (108, 'POUCO URGENTE', 4, 2, 'TOSSE PRODUTIVA', 'A INFECÇÃO RESPIRATÓRIA GERALMENTE CAUSA TOSSE COM ESCARRO DE QUALQUER COR, FREQUENTEMENTE PURULENTO.'),
    (108, 'POUCO URGENTE', 4, 3, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (108, 'POUCO URGENTE', 4, 4, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (108, 'POUCO URGENTE', 4, 5, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (108, 'POUCO URGENTE', 4, 6, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (109, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (109, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (109, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (109, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (109, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (109, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (109, 'MUITO URGENTE', 2, 2, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (109, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (109, 'MUITO URGENTE', 2, 4, 'ALTO RISCO DE AUTOAGRESSÃO', 'UMA AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE QUE TEM PASSADO IMPORTANTE DE  AUTOAGRESSÃO E ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR OU ESTÁ TENTANDO IR EMBORA PARA TAL FINALIDADE É DE ALTO RISCO.'),
    (109, 'MUITO URGENTE', 2, 5, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (109, 'MUITO URGENTE', 2, 6, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (109, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (109, 'URGENTE', 3, 2, 'AGITAÇÃO PSICOMOTORA', 'PACIENTE QUE ESTÁ FÍSICO E/OU EMOCIONALMENTE MUITO PERTURBADO (ANGÚSTIA PERCEPTÍVEL).'),
    (109, 'URGENTE', 3, 3, 'RISCO MODERADO DE AUTOAGRESSÃO', 'AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE SEM PASSADO IMPORTANTE DE AUTOAGRESSÃO, QUE NÃO ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR NEM TENTANDO IR EMBORA PARA TAL, MAS MANIFESTA DESEJO DE SE MACHUCAR, ESTÁ EM RISCO MODERADO.'),
    (109, 'URGENTE', 3, 4, 'HISTÓRIA PSIQUIÁTRICA IMPORTANTE', 'HISTÓRIA DE EVENTO OU DOENÇA PSIQUIÁTRICA SIGNIFICATIVA.'),
    (109, 'URGENTE', 3, 5, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (109, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (109, 'URGENTE', 3, 7, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (110, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (110, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (110, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (110, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (110, 'MUITO URGENTE', 2, 1, 'PROSTRAÇÃO, HIPOTONIA', 'PAIS DESCREVEM A CRIANÇA COMO "MOLINHA¿. O TÔNUS GERALMENTE ESTÁ DIMINUÍDO (O SINAL MAIS CARACTERÍSTICO É A CABEÇA CAÍDA).'),
    (110, 'MUITO URGENTE', 2, 2, 'RESPOSTA À VOZ OU À DOR APENAS', 'RESPOSTA A ESTÍMULOS DOLOROSOS. O ESTÍMULO PERIFÉRICO PADRÃO DEVE SER REALIZADO PRESSIONANDO UMA CANETA NO LEITO UNGUEAL DOS DEDOS DAS MÃOS. ESTE TIPO DE ESTÍMULO NÃO DEVE SER FEITO NO HÁLUX, POIS O REFLEXO ESPINHAL PODE CAUSAR FLEXÃO MESMO NA MORTE ENCEFÁLICA. PRESSÃO SUPRAORBITÁRIA TAMBÉM NÃO DEVE SER UTILIZADA, POIS PODE PRODUZIR O REFLEXO DE CONTORÇÃO DE FACE. RESPOSTA AO ESTÍMULO DA VOZ. NÃO É NECESSÁRIO GRITAR O NOME DO PACIENTE. CRIANÇAS PODEM NÃO RESPONDER, POR ESTAREM COM MEDO.'),
    (110, 'MUITO URGENTE', 2, 3, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (110, 'MUITO URGENTE', 2, 4, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (110, 'MUITO URGENTE', 2, 5, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (110, 'MUITO URGENTE', 2, 6, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (110, 'MUITO URGENTE', 2, 7, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (110, 'URGENTE', 3, 1, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (110, 'URGENTE', 3, 2, 'INCAPAZ DE SE ALIMENTAR', 'ISTO É GERALMENTE RELATADO PELOS PAIS. CRIANÇA QUE NÃO INGERE ADEQUADAMENTE SÓLIDO OU LÍQUIDO VIA ORAL.'),
    (110, 'URGENTE', 3, 3, 'INCONSOLÁVEL PELOS PAIS', 'RELATO DE CHORO OU SOFRIMENTO, NÃO RESPONDEM ÀS TENTATIVAS DE ACALANTO DOS PAIS.'),
    (110, 'URGENTE', 3, 4, 'CHORO PROLONGADO OU ININTERRUPTO', 'RELATO DE CHORO CONTÍNUO POR 2 HORAS OU MAIS.'),
    (110, 'URGENTE', 3, 5, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (110, 'URGENTE', 3, 6, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (110, 'POUCO URGENTE', 4, 1, 'COMPORTAMENTO ATÍPICO', 'CRIANÇA COM COMPORTAMENTO NÃO HABITUAL EM DADA SITUAÇÃO. OS CUIDADORES FREQUENTEMENTE FORNECEM ESTA INFORMAÇÃO ESPONTANEAMENTE. A CRIANÇA PODE ESTAR RABUGENTA, INDÓCIL, IRRITADIÇA OU COM COMPORTAMENTO DIFERENTE DO SEU HABITUAL.'),
    (110, 'POUCO URGENTE', 4, 2, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (110, 'POUCO URGENTE', 4, 3, 'SINAIS DE DOR LEVE RECENTE', 'CRIANÇAS PEQUENAS E BEBÊS NÃO CONSEGUEM QUEIXAR. ELES PODEM CHORAR OCASIONALMENTE E PORTAR DE FORMA ATÍPICA.'),
    (110, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (111, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (111, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (111, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (111, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (111, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (111, 'MUITO URGENTE', 2, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (111, 'MUITO URGENTE', 2, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (111, 'MUITO URGENTE', 2, 3, 'SINAIS DE MENINGISMO', 'CLASSICAMENTE RIGIDEZ DE NUCA ASSOCIADA A CEFALEIA E FOTOFOBIA. EM CRIANÇAS PEQUENAS PODE HAVER IRRITABILIDADE À MANIPULAÇÃO, CHORO ESTRIDENTE E ABAULAMENTO DE FONTANELA.'),
    (111, 'MUITO URGENTE', 2, 4, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (111, 'MUITO URGENTE', 2, 5, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (111, 'MUITO URGENTE', 2, 6, 'INÍCIO ABRUPTO', 'INÍCIO EM SEGUNDOS OU MINUTOS. PODE ACORDAR O PACIENTE.'),
    (111, 'MUITO URGENTE', 2, 7, 'PERDA TOTAL DA VISÃO AGUDA', 'PERDA DA VISÃO EM UM OU AMBOS OS OLHOS NAS ÚLTIMAS 24H E QUE NÃO VOLTOU AO NORMAL.'),
    (111, 'MUITO URGENTE', 2, 8, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (111, 'MUITO URGENTE', 2, 9, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (111, 'MUITO URGENTE', 2, 10, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (111, 'MUITO URGENTE', 2, 11, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (111, 'URGENTE', 3, 1, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (111, 'URGENTE', 3, 2, 'REDUÇÃO RECENTE DA ACUIDADE VISUAL', 'QUALQUER  REDUÇÃO DA ACUIDADE VISUAL OCORRIDA HÁ MENOS DE SETE DIAS.'),
    (111, 'URGENTE', 3, 3, 'COURO CABELUDO TEMPORAL DOLORIDO', 'SENSIBILIDADE OU DOLORIMENTO À PALPAÇÃO DA REGIÃO TEMPORAL (PRINCIPALMENTE SOBRE A ARTÉRIA TEMPORAL).'),
    (111, 'URGENTE', 3, 4, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (111, 'URGENTE', 3, 5, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (111, 'URGENTE', 3, 6, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (111, 'URGENTE', 3, 7, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (111, 'URGENTE', 3, 8, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (111, 'URGENTE', 3, 9, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (111, 'URGENTE', 3, 10, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (111, 'POUCO URGENTE', 4, 1, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (111, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (111, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (111, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (111, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (112, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (112, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (112, 'EMERGÊNCIA', 1, 3, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (112, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (112, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (112, 'EMERGÊNCIA', 1, 6, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (112, 'MUITO URGENTE', 2, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (112, 'MUITO URGENTE', 2, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (112, 'MUITO URGENTE', 2, 3, 'SINAIS DE MENINGISMO', 'CLASSICAMENTE RIGIDEZ DE NUCA ASSOCIADA A CEFALEIA E FOTOFOBIA. EM CRIANÇAS PEQUENAS PODE HAVER IRRITABILIDADE À MANIPULAÇÃO, CHORO ESTRIDENTE E ABAULAMENTO DE FONTANELA.'),
    (112, 'MUITO URGENTE', 2, 4, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (112, 'MUITO URGENTE', 2, 5, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (112, 'MUITO URGENTE', 2, 6, 'HISTÓRIA DE OVERDOSE OU ENVENENAMENTO', 'ESTA INFORMAÇÃO PODE VIR DE OUTROS OU PODE SER DEDUZIDA NA PRESENÇA DE CAIXAS DE REMÉDIOS VAZIAS, ENTRE OUTRAS.'),
    (112, 'MUITO URGENTE', 2, 7, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (112, 'MUITO URGENTE', 2, 8, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (112, 'MUITO URGENTE', 2, 9, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (112, 'MUITO URGENTE', 2, 10, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (112, 'MUITO URGENTE', 2, 11, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (112, 'URGENTE', 3, 1, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (112, 'URGENTE', 3, 2, 'HISTÓRIA DE TRAUMA CRANIOENCEFÁLICO', 'HISTÓRIA DE TRAUMA FÍSICO ENVOLVENDO A CABEÇA. GERALMENTE ISSO SERÁ RELATADO PELO PACIENTE, MAS SE ELE ESTEVE INCONSCIENTE, A HISTÓRIA DEVERÁ SER COLHIDA DE UMA TESTEMUNHA CONFIÁVEL.'),
    (112, 'URGENTE', 3, 3, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (112, 'URGENTE', 3, 4, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (112, 'URGENTE', 3, 5, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (112, 'URGENTE', 3, 6, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (112, 'POUCO URGENTE', 4, 1, 'CEFALEIA', 'QUALQUER DOR AO REDOR DA CABEÇA NÃO RELACIONADA A ALGUMA ESTRUTURA ANATÔMICA ESPECIAL. A DOR FACIAL NÃO ESTÁ INCLUÍDA.'),
    (112, 'POUCO URGENTE', 4, 2, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (112, 'POUCO URGENTE', 4, 3, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (112, 'POUCO URGENTE', 4, 4, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (112, 'POUCO URGENTE', 4, 5, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (112, 'POUCO URGENTE', 4, 6, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (113, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (113, 'EMERGÊNCIA', 1, 2, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (113, 'EMERGÊNCIA', 1, 3, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (113, 'EMERGÊNCIA', 1, 4, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (113, 'EMERGÊNCIA', 1, 5, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (113, 'EMERGÊNCIA', 1, 6, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (113, 'MUITO URGENTE', 2, 1, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (113, 'MUITO URGENTE', 2, 2, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (113, 'MUITO URGENTE', 2, 3, 'TRAUMA OCULAR PENETRANTE', 'EVENTO TRAUMÁTICO FÍSICO RECENTE COM PERFURAÇÃO DO GLOBO OCULAR.'),
    (113, 'MUITO URGENTE', 2, 4, 'INGESTÃO DE OBJETO PERIGOSO', 'INGESTÃO DE OBJETO PERIGOSO OU POTENCIALMENTE PERIGOSO QUE POSSA AMEAÇAR A VIDA COMO POR EXEMPLO: BATERIA, IMÃ, LÂMINAS.'),
    (113, 'MUITO URGENTE', 2, 5, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (113, 'MUITO URGENTE', 2, 6, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (113, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (113, 'URGENTE', 3, 2, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (113, 'URGENTE', 3, 3, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (113, 'POUCO URGENTE', 4, 1, 'OLHO VERMELHO', 'QUALQUER VERMELHIDÃO DO OLHO. PODE OU NÃO HAVER DOR. A VERMELHIDÃO DO OLHO PODE SER DIFUSA OU PARCIAL.'),
    (113, 'POUCO URGENTE', 4, 2, 'INFLAMAÇÃO LOCAL', 'IMPLICA DOR, INCHAÇO E VERMELHIDÃO, RESTRITA A UMA ÁREA DEFINIDA.'),
    (113, 'POUCO URGENTE', 4, 3, 'INFECÇÃO LOCAL', 'MANIFESTA-SE GERALMENTE COMO INFLAMAÇÃO (DOR, INCHAÇO E VERMELHIDÃO) RESTRITA A UMA ÁREA DEFINIDA, COM OU SEM COLEÇÃO DE PUS.'),
    (113, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.');
INSERT INTO discriminadores (id_fluxograma, classificacao, prioridade, ordem, pergunta, explicacao) VALUES
    (113, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (114, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (114, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (114, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (114, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (114, 'MUITO URGENTE', 2, 1, 'RESPOSTA À VOZ OU À DOR APENAS', 'RESPOSTA A ESTÍMULOS DOLOROSOS. O ESTÍMULO PERIFÉRICO PADRÃO DEVE SER REALIZADO PRESSIONANDO UMA CANETA NO LEITO UNGUEAL DOS DEDOS DAS MÃOS. ESTE TIPO DE ESTÍMULO NÃO DEVE SER FEITO NO HÁLUX, POIS O REFLEXO ESPINHAL PODE CAUSAR FLEXÃO MESMO NA MORTE ENCEFÁLICA. PRESSÃO SUPRAORBITÁRIA TAMBÉM NÃO DEVE SER UTILIZADA, POIS PODE PRODUZIR O REFLEXO DE CONTORÇÃO DE FACE. RESPOSTA AO ESTÍMULO DA VOZ. NÃO É NECESSÁRIO GRITAR O NOME DO PACIENTE. CRIANÇAS PODEM NÃO RESPONDER, POR ESTAREM COM MEDO.'),
    (114, 'MUITO URGENTE', 2, 2, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (114, 'MUITO URGENTE', 2, 3, 'ALTO RISCO DE AUTOAGRESSÃO', 'UMA AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE QUE TEM PASSADO IMPORTANTE DE  AUTOAGRESSÃO E ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR OU ESTÁ TENTANDO IR EMBORA PARA TAL FINALIDADE É DE ALTO RISCO.'),
    (114, 'MUITO URGENTE', 2, 4, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (114, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (114, 'URGENTE', 3, 2, 'SINAIS DE DESIDRATAÇÃO', 'LÍNGUA SECA, ENOFTALMIA (OLHOS FUNDOS), TURGOR PASTOSO E, EM BEBÊS PEQUENOS, FONTANELA BAIXA. GERALMENTE, HÁ OLIGÚRIA (DIMINUIÇÃO DA DIURESE).'),
    (114, 'URGENTE', 3, 3, 'ERUPÇÃO OU VESÍCULAS DISSEMINADAS', 'QUALQUER ERUPÇÃO, INCLUSIVE AS SECRETANTES OU BOLHOSAS, COBRINDO MAIS DE 10% DA SUPERFÍCIE CORPORAL.'),
    (114, 'URGENTE', 3, 4, 'AGITAÇÃO PSICOMOTORA', 'PACIENTE QUE ESTÁ FÍSICO E/OU EMOCIONALMENTE MUITO PERTURBADO (ANGÚSTIA PERCEPTÍVEL).'),
    (114, 'URGENTE', 3, 5, 'TRAUMA VAGINAL', 'QUALQUER HISTÓRIA OU OUTRA EVIDÊNCIA DE TRAUMA NA VAGINA.'),
    (114, 'URGENTE', 3, 6, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (114, 'URGENTE', 3, 7, 'HISTÓRIA DE TRAUMA CRANIOENCEFÁLICO', 'HISTÓRIA DE TRAUMA FÍSICO ENVOLVENDO A CABEÇA. GERALMENTE ISSO SERÁ RELATADO PELO PACIENTE, MAS SE ELE ESTEVE INCONSCIENTE, A HISTÓRIA DEVERÁ SER COLHIDA DE UMA TESTEMUNHA CONFIÁVEL.'),
    (114, 'URGENTE', 3, 8, 'RISCO MODERADO DE AUTOAGRESSÃO', 'AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE SEM PASSADO IMPORTANTE DE AUTOAGRESSÃO, QUE NÃO ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR NEM TENTANDO IR EMBORA PARA TAL, MAS MANIFESTA DESEJO DE SE MACHUCAR, ESTÁ EM RISCO MODERADO.'),
    (114, 'URGENTE', 3, 9, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (115, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (115, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (115, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (115, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (115, 'EMERGÊNCIA', 1, 5, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (115, 'MUITO URGENTE', 2, 1, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (115, 'MUITO URGENTE', 2, 2, 'RESPOSTA À VOZ OU À DOR APENAS', 'RESPOSTA A ESTÍMULOS DOLOROSOS. O ESTÍMULO PERIFÉRICO PADRÃO DEVE SER REALIZADO PRESSIONANDO UMA CANETA NO LEITO UNGUEAL DOS DEDOS DAS MÃOS. ESTE TIPO DE ESTÍMULO NÃO DEVE SER FEITO NO HÁLUX, POIS O REFLEXO ESPINHAL PODE CAUSAR FLEXÃO MESMO NA MORTE ENCEFÁLICA. PRESSÃO SUPRAORBITÁRIA TAMBÉM NÃO DEVE SER UTILIZADA, POIS PODE PRODUZIR O REFLEXO DE CONTORÇÃO DE FACE. RESPOSTA AO ESTÍMULO DA VOZ. NÃO É NECESSÁRIO GRITAR O NOME DO PACIENTE. CRIANÇAS PODEM NÃO RESPONDER, POR ESTAREM COM MEDO.'),
    (115, 'MUITO URGENTE', 2, 3, 'SINAIS DE MENINGISMO', 'CLASSICAMENTE RIGIDEZ DE NUCA ASSOCIADA A CEFALEIA E FOTOFOBIA. EM CRIANÇAS PEQUENAS PODE HAVER IRRITABILIDADE À MANIPULAÇÃO, CHORO ESTRIDENTE E ABAULAMENTO DE FONTANELA.'),
    (115, 'MUITO URGENTE', 2, 4, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (115, 'MUITO URGENTE', 2, 5, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (115, 'MUITO URGENTE', 2, 6, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (115, 'MUITO URGENTE', 2, 7, 'HISTÓRIA DE OVERDOSE OU ENVENENAMENTO', 'ESTA INFORMAÇÃO PODE VIR DE OUTROS OU PODE SER DEDUZIDA NA PRESENÇA DE CAIXAS DE REMÉDIOS VAZIAS, ENTRE OUTRAS.'),
    (115, 'MUITO URGENTE', 2, 8, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (115, 'MUITO URGENTE', 2, 9, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (115, 'MUITO URGENTE', 2, 10, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (115, 'MUITO URGENTE', 2, 11, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (115, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (115, 'URGENTE', 3, 2, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (115, 'URGENTE', 3, 3, 'CHORO PROLONGADO OU ININTERRUPTO', 'RELATO DE CHORO CONTÍNUO POR 2 HORAS OU MAIS.'),
    (115, 'URGENTE', 3, 4, 'NÃO SE ALIMENTA', 'CRIANÇA QUE NÃO INGERE NADA SÓLIDO OU LÍQUIDO COMO DE HÁBITO. CRIANÇA QUE SE ALIMENTA, MAS VOMITA LOGO APÓS TAMBÉM PREENCHE ESTE CRITÉRIO.'),
    (115, 'URGENTE', 3, 5, 'NÃO ENTRETÍVEL', 'CRIANÇA ANGUSTIADA POR DOR OU OUTROS FATORES E QUE É INCAPAZ DE SE DISTRAIR COM CONVERSAS OU BRINCADEIRAS.'),
    (115, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (115, 'URGENTE', 3, 7, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (115, 'URGENTE', 3, 8, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (115, 'POUCO URGENTE', 4, 1, 'COMPORTAMENTO ATÍPICO', 'CRIANÇA COM COMPORTAMENTO NÃO HABITUAL EM DADA SITUAÇÃO. OS CUIDADORES FREQUENTEMENTE FORNECEM ESTA INFORMAÇÃO ESPONTANEAMENTE. A CRIANÇA PODE ESTAR RABUGENTA, INDÓCIL, IRRITADIÇA OU COM COMPORTAMENTO DIFERENTE DO SEU HABITUAL.'),
    (115, 'POUCO URGENTE', 4, 2, 'SINAIS DE DOR LEVE RECENTE', 'CRIANÇAS PEQUENAS E BEBÊS NÃO CONSEGUEM QUEIXAR. ELES PODEM CHORAR OCASIONALMENTE E PORTAR DE FORMA ATÍPICA.'),
    (115, 'POUCO URGENTE', 4, 3, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (115, 'POUCO URGENTE', 4, 4, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (115, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (116, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (116, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (116, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (116, 'MUITO URGENTE', 2, 1, 'COMPROMETIMENTO VASCULAR DISTAL', 'HAVERÁ ASSOCIAÇÃO DE PALIDEZ, ESFRIAMENTO, ALTERAÇÃO DA SENSIBILIDADE E/OU DOR COM OU SEM PULSO DISTAL À LESÃO.'),
    (116, 'MUITO URGENTE', 2, 2, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (116, 'MUITO URGENTE', 2, 3, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (116, 'MUITO URGENTE', 2, 4, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (116, 'MUITO URGENTE', 2, 5, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (116, 'MUITO URGENTE', 2, 6, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (116, 'MUITO URGENTE', 2, 7, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (116, 'URGENTE', 3, 1, 'ARTICULAÇÃO QUENTE', 'QUALQUER AUMENTO DA TEMPERATURA EM TORNO DA ARTICULAÇÃO PREENCHE ESTE CRITÉRIO. GERALMENTE ESTÁ ASSOCIADA À VERMELHIDÃO.'),
    (116, 'URGENTE', 3, 2, 'DOR AO MOVIMENTO ARTICULAR', 'A DOR PODE OCORRER TANTO NA MOVIMENTAÇÃO ATIVA (DO PACIENTE) COMO PASSIVA (PELO EXAMINADOR) DA ARTICULAÇÃO.'),
    (116, 'URGENTE', 3, 3, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (116, 'URGENTE', 3, 4, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (116, 'URGENTE', 3, 5, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (116, 'URGENTE', 3, 6, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (116, 'POUCO URGENTE', 4, 1, 'DEFORMIDADE', 'ISTO É SEMPRE SUBJETIVO. INCLUI ANGULAÇÃO OU ROTAÇÃO ANORMAL.'),
    (116, 'POUCO URGENTE', 4, 2, 'INCHAÇO', 'QUALQUER AUMENTO ANORMAL NO TAMANHO.'),
    (116, 'POUCO URGENTE', 4, 3, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (116, 'POUCO URGENTE', 4, 4, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (116, 'POUCO URGENTE', 4, 5, 'SINAIS DE DOR LEVE RECENTE', 'CRIANÇAS PEQUENAS E BEBÊS NÃO CONSEGUEM QUEIXAR. ELES PODEM CHORAR OCASIONALMENTE E PORTAR DE FORMA ATÍPICA.'),
    (116, 'POUCO URGENTE', 4, 6, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (117, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (117, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (117, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (117, 'EMERGÊNCIA', 1, 4, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (117, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (117, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (117, 'MUITO URGENTE', 2, 2, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (117, 'MUITO URGENTE', 2, 3, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (117, 'MUITO URGENTE', 2, 4, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (117, 'MUITO URGENTE', 2, 5, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (117, 'MUITO URGENTE', 2, 6, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (117, 'MUITO URGENTE', 2, 7, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (117, 'MUITO URGENTE', 2, 8, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (117, 'MUITO URGENTE', 2, 9, 'HISTÓRIA ALÉRGICA IMPORTANTE', 'SENSIBILIDADE CONHECIDA COM REAÇÃO GRAVE (POR EXEMPLO: NOZES, CAMARÃO, PICADA DE ABELHA).'),
    (117, 'MUITO URGENTE', 2, 10, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (117, 'MUITO URGENTE', 2, 11, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (117, 'MUITO URGENTE', 2, 12, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (117, 'MUITO URGENTE', 2, 13, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (117, 'MUITO URGENTE', 2, 14, 'DOR PRECORDIAL OU CARDÍACA', 'DOR NO MEIO DO PEITO, GERALMENTE EM APERTO OU PESO, QUE PODE IRRADIAR PARA O BRAÇO ESQUERDO OU PESCOÇO. PODE-SE ASSOCIAR A SUDORESE, NÁUSEAS, SENSAÇÃO DE LIPOTIMIA E/OU DOR EPIGÁSTRICA.'),
    (117, 'MUITO URGENTE', 2, 15, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (117, 'URGENTE', 3, 1, 'HISTÓRIA DE TRAUMA CRANIOENCEFÁLICO', 'HISTÓRIA DE TRAUMA FÍSICO ENVOLVENDO A CABEÇA. GERALMENTE ISSO SERÁ RELATADO PELO PACIENTE, MAS SE ELE ESTEVE INCONSCIENTE, A HISTÓRIA DEVERÁ SER COLHIDA DE UMA TESTEMUNHA CONFIÁVEL.'),
    (117, 'URGENTE', 3, 2, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (117, 'URGENTE', 3, 3, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (117, 'URGENTE', 3, 4, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (117, 'URGENTE', 3, 5, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (117, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (117, 'URGENTE', 3, 7, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (117, 'URGENTE', 3, 8, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (117, 'URGENTE', 3, 9, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (117, 'POUCO URGENTE', 4, 1, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (117, 'POUCO URGENTE', 4, 2, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (117, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (117, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (118, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (118, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (118, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (118, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (118, 'EMERGÊNCIA', 1, 5, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (118, 'MUITO URGENTE', 2, 1, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
