    (118, 'MUITO URGENTE', 2, 9, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (118, 'URGENTE', 3, 1, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (118, 'URGENTE', 3, 2, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (118, 'URGENTE', 3, 3, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
