    (118, 'POUCO URGENTE', 4, 6, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (119, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (119, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (119, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (119, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (119, 'MUITO URGENTE', 2, 1, 'PROSTRAÇÃO, HIPOTONIA', 'PAIS DESCREVEM A CRIANÇA COMO "MOLINHA¿. O TÔNUS GERALMENTE ESTÁ DIMINUÍDO (O SINAL MAIS CARACTERÍSTICO É A CABEÇA CAÍDA).'),
    (119, 'MUITO URGENTE', 2, 2, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (119, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (119, 'MUITO URGENTE', 2, 4, 'NÃO REAGE AOS PAIS', 'NÃO REAGE DE FORMA ALGUMA AO ROSTO OU À VOZ DOS PAIS. REAÇÕES ANORMAIS E APARENTE PERDA DE RECONHECIMENTO DOS PAIS TAMBÉM SÃO SINAIS PREOCUPANTES.'),
    (119, 'MUITO URGENTE', 2, 5, 'VÔMITO DE SANGUE', 'EVIDÊNCIAS DE VÔMITO COM SANGUE. O SANGUE VOMITADO PODE SER FRESCO, RUTILANTE, ESCURECIDO OU EM BORRA DE CAFÉ.'),
    (119, 'MUITO URGENTE', 2, 6, 'EVACUAÇÃO DE SANGUE VIVO OU ESCURECIDO', 'EVIDÊNCIA DE SANGRAMENTO GASTRINTESTINAL ATIVO E/OU MACIÇO. PODERÁ HAVER EVACUAÇÃO DE SANGUE VERMELHO VIVO OU ESCURECIDO. QUANDO O TEMPO DO TRÂNSITO GASTRINTESTINAL AUMENTA, A EVACUAÇÃO SE TORNA PROGRESSIVAMENTE MAIS ESCURA ATÉ MELENA.'),
    (119, 'MUITO URGENTE', 2, 7, 'HISTÓRIA DE HEMORRAGIA DIGESTIVA IMPORTANTE', 'QUALQUER PASSADO DE SANGRAMENTO GASTRINTESTINAL MACIÇO OU ASSOCIADO A VARIZES ESOFAGIANAS.'),
    (119, 'MUITO URGENTE', 2, 8, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (119, 'MUITO URGENTE', 2, 9, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (119, 'MUITO URGENTE', 2, 10, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (119, 'MUITO URGENTE', 2, 11, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (119, 'MUITO URGENTE', 2, 12, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (119, 'MUITO URGENTE', 2, 13, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (119, 'URGENTE', 3, 1, 'HISTÓRIA AGUDA DE VÔMITO DE SANGUE', 'QUALQUER RELATO DE HEMATÊMESE FRANCA, VÔMITO DE SANGUE ALTERADO (BORRA DE CAFÉ) OU SANGUE MISTURADO AO VÔMITO NAS ÚLTIMAS 24 HORAS PREENCHE ESTE CRITÉRIO.'),
    (119, 'URGENTE', 3, 2, 'FEZES PRETAS OU FEZES EM GROSELHA', 'QUALQUER RELATO DE FEZES ENEGRECIDAS PREENCHE ESTE CRITÉRIO. FEZES EM GROSELHA SÃO DE COLORAÇÃO VERMELHO ESCURO, CLASSICAMENTE VISTAS EM INTUSSUSCEPÇÃO. QUALQUER RELATO DESSES TIPOS DE FEZES PREENCHE ESTE CRITÉRIO.'),
    (119, 'URGENTE', 3, 3, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (119, 'URGENTE', 3, 4, 'SINAIS DE DESIDRATAÇÃO', 'LÍNGUA SECA, ENOFTALMIA (OLHOS FUNDOS), TURGOR PASTOSO E, EM BEBÊS PEQUENOS, FONTANELA BAIXA. GERALMENTE, HÁ OLIGÚRIA (DIMINUIÇÃO DA DIURESE).'),
    (119, 'URGENTE', 3, 5, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (119, 'URGENTE', 3, 6, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (119, 'URGENTE', 3, 7, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (119, 'URGENTE', 3, 8, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (119, 'POUCO URGENTE', 4, 1, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (119, 'POUCO URGENTE', 4, 2, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (119, 'POUCO URGENTE', 4, 3, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (119, 'POUCO URGENTE', 4, 4, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (119, 'POUCO URGENTE', 4, 5, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (119, 'POUCO URGENTE', 4, 6, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (120, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (120, 'EMERGÊNCIA', 1, 2, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (120, 'EMERGÊNCIA', 1, 3, 'BABA-SE', 'SALIVA SAINDO PELA BOCA POR INCAPACIDADE DE ENGOLIR.'),
    (120, 'EMERGÊNCIA', 1, 4, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (120, 'EMERGÊNCIA', 1, 5, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (120, 'MUITO URGENTE', 2, 1, 'LESÃO POR INALAÇÃO', 'HISTÓRIA DE CONFINAMENTO EM ESPAÇO COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE ASPIRAÇÃO DE FUMAÇA. FULIGEM EM TORNO DA BOCA E NARIZ, ALÉM DE ROUQUIDÃO, ESTARÁ PRESENTE. HISTÓRIA É TAMBÉM A FORMA MAIS SEGURA DE SE DIAGNOSTICAR INALAÇÃO DE AGENTES QUÍMICOS - PODE NÃO HAVER ALGUM OUTRO SINAL.'),
    (120, 'MUITO URGENTE', 2, 2, 'FRASES ENTRECORTADAS', 'DOENTES COM DIFICULDADE RESPIRATÓRIA TÃO GRANDE QUE NÃO CONSEGUEM NEM ARTICULAR FRASES CURTAS NUMA SÓ RESPIRAÇÃO.'),
    (120, 'MUITO URGENTE', 2, 3, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (120, 'MUITO URGENTE', 2, 4, 'HEMOPTISE', 'SANGUE AERADO EMITIDO COM O ESFORÇO DA TOSSE OBSERVADO PELO CLASSIFICADOR.'),
    (120, 'MUITO URGENTE', 2, 5, 'EXAUSTÃO', 'PACIENTES EM EXAUSTÃO RESPIRATÓRIA PERECEM REDUZIR O ESFORÇO QUE FAZEM PARA RESPIRAR APESAR DE SE MANTEREM EM INSUFICIÊNCIA RESPIRATÓRIA CONTÍNUA. É PRÉ-TERMINAL.'),
    (120, 'MUITO URGENTE', 2, 6, 'PFE MUITO BAIXO', 'PICO DE FLUXO EXPIRATÓRIO DE 33% OU MENOS DO PREVISTO DE ACORDO COM A IDADE E SEXO DO PACIENTE (VER ESCALAS ANEXAS). ALGUNS PACIENTES CONHECEM SEU MELHOR PFE E ESTE DADO PODE SER USADO. SE A PROPORÇÃO DO VALOR MEDIDO FOR IGUAL OU INFERIOR A 33% DO PREVISTO, ESTE CRITÉRIO É PREENCHIDO.'),
    (120, 'MUITO URGENTE', 2, 7, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (120, 'MUITO URGENTE', 2, 8, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (120, 'MUITO URGENTE', 2, 9, 'HISTÓRIA RESPIRATÓRIA SIGNIFICATIVA', 'HISTÓRIA PRÉVIA DE CONDIÇÕES RESPIRATÓRIAS AMEAÇADORAS DA VIDA (POR EXEMPLO: DOENÇA PULMONAR OBSTRUTIVA CRÔNICA - DPOC, ASMA LÁBIL, USO DOMICILIAR DE O2, VENTILAÇÃO NÃO INVASIVA OU INVASIVA).'),
    (120, 'MUITO URGENTE', 2, 10, 'INÍCIO AGUDO APÓS TRAUMA', 'INÍCIO IMEDIATO DOS SINTOMAS EM 24H APÓS UM TRAUMA FÍSICO.'),
    (120, 'MUITO URGENTE', 2, 11, 'DOR PRECORDIAL OU CARDÍACA', 'DOR NO MEIO DO PEITO, GERALMENTE EM APERTO OU PESO, QUE PODE IRRADIAR PARA O BRAÇO ESQUERDO OU PESCOÇO. PODE-SE ASSOCIAR A SUDORESE, NÁUSEAS, SENSAÇÃO DE LIPOTIMIA E/OU DOR EPIGÁSTRICA.'),
    (120, 'MUITO URGENTE', 2, 12, 'DOR EPIGÁSTRICA', 'DOR OU DESCONFORTO NO EPIGÁSTRIO ACOMPANHADA DE NÁUSEA, SUDORESE, SENSAÇÃO DE TONTEIRA.'),
    (120, 'MUITO URGENTE', 2, 13, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (120, 'MUITO URGENTE', 2, 14, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (120, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (120, 'URGENTE', 3, 2, 'EXPOSIÇÃO À FUMAÇA', 'HISTÓRIA DE CONFINAMENTO EM LUGAR COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE EXPOSIÇÃO À FUMAÇA. PODE HAVER FULIGEM EM TORNO DA BOCA E NARIZ.'),
    (120, 'URGENTE', 3, 3, 'PFE BAIXO', 'PICO DE FLUXO EXPIRATÓRIO DE 50% OU MENOS DO PREVISTO DE ACORDO COM A IDADE E SEXO DO PACIENTE (VER ESCALAS ANEXAS). ALGUNS PACIENTES CONHECEM SEU MELHOR PFE E ESTE DADO PODE SER USADO. SE A PROPORÇÃO DO VALOR MEDIDO FOR IGUAL OU INFERIOR A 50% DO PREVISTO, ESTE CRITÉRIO É PREENCHIDO.'),
    (120, 'URGENTE', 3, 4, 'HISTÓRIA DE HEMOPTISE', 'QUALQUER RELATO DE SANGUE AERADO EMITIDO COM O ESFORÇO DA TOSSE PREENCHE ESTE CRITÉRIO.'),
    (120, 'URGENTE', 3, 5, 'DOR PLEURÍTICA', 'DOR LOCALIZADA NO TÓRAX QUE PIORA COM RESPIRAÇÃO, TOSSE OU ESPIRRO. DOR VENTILATÓRIO-DEPENDENTE.'),
    (120, 'URGENTE', 3, 6, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (120, 'POUCO URGENTE', 4, 1, 'CHIEIRA', 'PODE HAVER UMA SIBILÂNCIA AUDÍVEL OU SÓ UMA SENSAÇÃO DE CHIADO. OBSTRUÇÃO MAIS GRAVE DE VIAS AÉREAS PODE SER SILENCIOSA (NÃO PASSA NENHUM AR).'),
    (120, 'POUCO URGENTE', 4, 2, 'TOSSE PRODUTIVA', 'A INFECÇÃO RESPIRATÓRIA GERALMENTE CAUSA TOSSE COM ESCARRO DE QUALQUER COR, FREQUENTEMENTE PURULENTO.'),
    (120, 'POUCO URGENTE', 4, 3, 'TRAUMA TORÁCICO', 'QUALQUER TRAUMA ABAIXO DA CLAVÍCULA E ACIMA DA ÚLTIMA COSTELA. TRAUMA NA PARTE INFERIOR DO TÓRAX PODE CAUSAR LESÃO DE ÓRGÃOS ABDOMINAIS.'),
    (120, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (121, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (121, 'EMERGÊNCIA', 1, 2, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (121, 'EMERGÊNCIA', 1, 3, 'BABA-SE', 'SALIVA SAINDO PELA BOCA POR INCAPACIDADE DE ENGOLIR.'),
    (121, 'EMERGÊNCIA', 1, 4, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (121, 'EMERGÊNCIA', 1, 5, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (121, 'EMERGÊNCIA', 1, 6, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (121, 'MUITO URGENTE', 2, 1, 'LESÃO POR INALAÇÃO', 'HISTÓRIA DE CONFINAMENTO EM ESPAÇO COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE ASPIRAÇÃO DE FUMAÇA. FULIGEM EM TORNO DA BOCA E NARIZ, ALÉM DE ROUQUIDÃO, ESTARÁ PRESENTE. HISTÓRIA É TAMBÉM A FORMA MAIS SEGURA DE SE DIAGNOSTICAR INALAÇÃO DE AGENTES QUÍMICOS - PODE NÃO HAVER ALGUM OUTRO SINAL.'),
    (121, 'MUITO URGENTE', 2, 2, 'FRASES ENTRECORTADAS', 'DOENTES COM DIFICULDADE RESPIRATÓRIA TÃO GRANDE QUE NÃO CONSEGUEM NEM ARTICULAR FRASES CURTAS NUMA SÓ RESPIRAÇÃO.'),
    (121, 'MUITO URGENTE', 2, 3, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (121, 'MUITO URGENTE', 2, 4, 'ESFORÇO RESPIRATÓRIO AUMENTADO', 'HÁ AUMENTO DA FREQUÊNCIA RESPIRATÓRIA, USO DE MUSCULATURA ACESSÓRIA E RONCOS.'),
    (121, 'MUITO URGENTE', 2, 5, 'EXAUSTÃO', 'PACIENTES EM EXAUSTÃO RESPIRATÓRIA PERECEM REDUZIR O ESFORÇO QUE FAZEM PARA RESPIRAR APESAR DE SE MANTEREM EM INSUFICIÊNCIA RESPIRATÓRIA CONTÍNUA. É PRÉ-TERMINAL.'),
    (121, 'MUITO URGENTE', 2, 6, 'HEMOPTISE', 'SANGUE AERADO EMITIDO COM O ESFORÇO DA TOSSE OBSERVADO PELO CLASSIFICADOR.'),
    (121, 'MUITO URGENTE', 2, 7, 'PFE MUITO BAIXO', 'PICO DE FLUXO EXPIRATÓRIO DE 33% OU MENOS DO PREVISTO DE ACORDO COM A IDADE E SEXO DO PACIENTE (VER ESCALAS ANEXAS). ALGUNS PACIENTES CONHECEM SEU MELHOR PFE E ESTE DADO PODE SER USADO. SE A PROPORÇÃO DO VALOR MEDIDO FOR IGUAL OU INFERIOR A 33% DO PREVISTO, ESTE CRITÉRIO É PREENCHIDO.');
INSERT INTO discriminadores (id_fluxograma, classificacao, prioridade, ordem, pergunta, explicacao) VALUES
    (121, 'MUITO URGENTE', 2, 8, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (121, 'MUITO URGENTE', 2, 9, 'RESPOSTA À VOZ OU À DOR APENAS', 'RESPOSTA A ESTÍMULOS DOLOROSOS. O ESTÍMULO PERIFÉRICO PADRÃO DEVE SER REALIZADO PRESSIONANDO UMA CANETA NO LEITO UNGUEAL DOS DEDOS DAS MÃOS. ESTE TIPO DE ESTÍMULO NÃO DEVE SER FEITO NO HÁLUX, POIS O REFLEXO ESPINHAL PODE CAUSAR FLEXÃO MESMO NA MORTE ENCEFÁLICA. PRESSÃO SUPRAORBITÁRIA TAMBÉM NÃO DEVE SER UTILIZADA, POIS PODE PRODUZIR O REFLEXO DE CONTORÇÃO DE FACE. RESPOSTA AO ESTÍMULO DA VOZ. NÃO É NECESSÁRIO GRITAR O NOME DO PACIENTE. CRIANÇAS PODEM NÃO RESPONDER, POR ESTAREM COM MEDO.'),
    (121, 'MUITO URGENTE', 2, 10, 'HISTÓRIA RESPIRATÓRIA SIGNIFICATIVA', 'HISTÓRIA PRÉVIA DE CONDIÇÕES RESPIRATÓRIAS AMEAÇADORAS DA VIDA (POR EXEMPLO: DOENÇA PULMONAR OBSTRUTIVA CRÔNICA - DPOC, ASMA LÁBIL, USO DOMICILIAR DE O2, VENTILAÇÃO NÃO INVASIVA OU INVASIVA).'),
    (121, 'MUITO URGENTE', 2, 11, 'INÍCIO AGUDO APÓS TRAUMA', 'INÍCIO IMEDIATO DOS SINTOMAS EM 24H APÓS UM TRAUMA FÍSICO.'),
    (121, 'MUITO URGENTE', 2, 12, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (121, 'MUITO URGENTE', 2, 13, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (121, 'MUITO URGENTE', 2, 14, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (121, 'MUITO URGENTE', 2, 15, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (121, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (121, 'URGENTE', 3, 2, 'EXPOSIÇÃO À FUMAÇA', 'HISTÓRIA DE CONFINAMENTO EM LUGAR COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE EXPOSIÇÃO À FUMAÇA. PODE HAVER FULIGEM EM TORNO DA BOCA E NARIZ.'),
    (121, 'URGENTE', 3, 3, 'PFE BAIXO', 'PICO DE FLUXO EXPIRATÓRIO DE 50% OU MENOS DO PREVISTO DE ACORDO COM A IDADE E SEXO DO PACIENTE (VER ESCALAS ANEXAS). ALGUNS PACIENTES CONHECEM SEU MELHOR PFE E ESTE DADO PODE SER USADO. SE A PROPORÇÃO DO VALOR MEDIDO FOR IGUAL OU INFERIOR A 50% DO PREVISTO, ESTE CRITÉRIO É PREENCHIDO.'),
    (121, 'URGENTE', 3, 4, 'HISTÓRIA DE HEMOPTISE', 'QUALQUER RELATO DE SANGUE AERADO EMITIDO COM O ESFORÇO DA TOSSE PREENCHE ESTE CRITÉRIO.'),
    (121, 'URGENTE', 3, 5, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (121, 'URGENTE', 3, 6, 'DOR PLEURÍTICA', 'DOR LOCALIZADA NO TÓRAX QUE PIORA COM RESPIRAÇÃO, TOSSE OU ESPIRRO. DOR VENTILATÓRIO-DEPENDENTE.'),
    (121, 'URGENTE', 3, 7, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (121, 'URGENTE', 3, 8, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (121, 'POUCO URGENTE', 4, 1, 'CHIEIRA', 'PODE HAVER UMA SIBILÂNCIA AUDÍVEL OU SÓ UMA SENSAÇÃO DE CHIADO. OBSTRUÇÃO MAIS GRAVE DE VIAS AÉREAS PODE SER SILENCIOSA (NÃO PASSA NENHUM AR).'),
    (121, 'POUCO URGENTE', 4, 2, 'TOSSE PRODUTIVA', 'A INFECÇÃO RESPIRATÓRIA GERALMENTE CAUSA TOSSE COM ESCARRO DE QUALQUER COR, FREQUENTEMENTE PURULENTO.'),
    (121, 'POUCO URGENTE', 4, 3, 'TRAUMA TORÁCICO', 'QUALQUER TRAUMA ABAIXO DA CLAVÍCULA E ACIMA DA ÚLTIMA COSTELA. TRAUMA NA PARTE INFERIOR DO TÓRAX PODE CAUSAR LESÃO DE ÓRGÃOS ABDOMINAIS.'),
    (121, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (122, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (122, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (122, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (122, 'EMERGÊNCIA', 1, 4, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (122, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (122, 'MUITO URGENTE', 2, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (122, 'MUITO URGENTE', 2, 2, 'ALTO RISCO DE AUTOAGRESSÃO', 'UMA AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE QUE TEM PASSADO IMPORTANTE DE  AUTOAGRESSÃO E ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR OU ESTÁ TENTANDO IR EMBORA PARA TAL FINALIDADE É DE ALTO RISCO.'),
    (122, 'MUITO URGENTE', 2, 3, 'ALTO RISCO DE AGREDIR OUTROS', 'A PRESENÇA DE UM RISCO POTENCIAL DE DANO A OUTROS PODE SER AVALIADO OBSERVANDO-SE A POSTURA (TENSA OU COM PUNHOS CERRADOS), O PADRÃO DE DISCURSO (ALTO, COM PALAVRAS AMEAÇADORAS) E O COMPORTAMENTO PSICOMOTOR (INQUIETUDE, ANDANDO). ALTO RISCO DEVE SER PRESUMIDO SE ARMAS E VÍTIMAS POTENCIAIS ESTÃO POR PERTO OU SE HOUVE PERDA DO AUTOCONTROLE.'),
    (122, 'MUITO URGENTE', 2, 4, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (122, 'URGENTE', 3, 1, 'RISCO MODERADO DE AUTOAGRESSÃO', 'AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE SEM PASSADO IMPORTANTE DE AUTOAGRESSÃO, QUE NÃO ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR NEM TENTANDO IR EMBORA PARA TAL, MAS MANIFESTA DESEJO DE SE MACHUCAR, ESTÁ EM RISCO MODERADO.'),
    (122, 'URGENTE', 3, 2, 'RISCO MODERADO DE AGREDIR OUTROS', 'RISCO POTENCIAL DE DANO A OUTROS PODE SER AVALIADO OBSERVANDO-SE A POSTURA DO PACIENTE (TENSA E PUNHOS CERRADOS), O PADRÃO DE DISCURSO (ALTO, AMEAÇADOR) E COMPORTAMENTO MOTOR (INQUIETUDE, ANDANDO). RISCO MODERADO DEVE SER PRESUMIDO SE HÁ QUALQUER INDÍCIO DE POTENCIAL AGRESSÃO A ALGUÉM.'),
    (122, 'URGENTE', 3, 3, 'AGITAÇÃO PSICOMOTORA', 'PACIENTE QUE ESTÁ FÍSICO E/OU EMOCIONALMENTE MUITO PERTURBADO (ANGÚSTIA PERCEPTÍVEL).'),
    (122, 'URGENTE', 3, 4, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (122, 'URGENTE', 3, 5, 'HISTÓRIA PSIQUIÁTRICA IMPORTANTE', 'HISTÓRIA DE EVENTO OU DOENÇA PSIQUIÁTRICA SIGNIFICATIVA.'),
    (122, 'URGENTE', 3, 6, 'COMPORTAMENTO CONTURBADOR', 'PACIENTE CUJO COMPORTAMENTO AFETA O BOM ANDAMENTO DO SERVIÇO. O PACIENTE PODE SER AMEAÇADOR.'),
    (123, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (123, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (123, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (123, 'MUITO URGENTE', 2, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (123, 'MUITO URGENTE', 2, 2, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (123, 'MUITO URGENTE', 2, 3, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (123, 'MUITO URGENTE', 2, 4, 'IMUNOSSUPRESSÃO CONHECIDA OU PROVÁVEL', 'QUALQUER PACIENTE EM USO DE DROGAS IMUNOSSUPRESSORAS (INCLUINDO USO PROLONGADO DE CORTICOIDE) OU COM DOENÇA QUE CAUSE IMUNOSSUPRESSÃO.'),
    (123, 'MUITO URGENTE', 2, 5, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (123, 'MUITO URGENTE', 2, 6, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (123, 'MUITO URGENTE', 2, 7, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (123, 'MUITO URGENTE', 2, 8, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (123, 'URGENTE', 3, 1, 'ERUPÇÃO OU VESÍCULAS DISSEMINADAS', 'QUALQUER ERUPÇÃO, INCLUSIVE AS SECRETANTES OU BOLHOSAS, COBRINDO MAIS DE 10% DA SUPERFÍCIE CORPORAL.'),
    (123, 'URGENTE', 3, 2, 'ARTICULAÇÃO QUENTE', 'QUALQUER AUMENTO DA TEMPERATURA EM TORNO DA ARTICULAÇÃO PREENCHE ESTE CRITÉRIO. GERALMENTE ESTÁ ASSOCIADA À VERMELHIDÃO.'),
    (123, 'URGENTE', 3, 3, 'DOR AO MOVIMENTO ARTICULAR', 'A DOR PODE OCORRER TANTO NA MOVIMENTAÇÃO ATIVA (DO PACIENTE) COMO PASSIVA (PELO EXAMINADOR) DA ARTICULAÇÃO.'),
    (123, 'URGENTE', 3, 4, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (123, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (123, 'URGENTE', 3, 6, 'DOR TESTICULAR', 'DOR NO TESTÍCULO.'),
    (123, 'URGENTE', 3, 7, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (123, 'POUCO URGENTE', 4, 1, 'CORRIMENTO', 'NO CONTEXTO DAS DOENÇAS SEXUALMENTE TRANSMISSÍVEIS, CORRIMENTO SIGNIFICA QUALQUER RELATO DE SECREÇÃO PENIANA OU VAGINAL ANORMAL.'),
    (123, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (123, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (123, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (123, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (124, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (124, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (124, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (124, 'MUITO URGENTE', 2, 1, 'VÔMITO DE SANGUE', 'EVIDÊNCIAS DE VÔMITO COM SANGUE. O SANGUE VOMITADO PODE SER FRESCO, RUTILANTE, ESCURECIDO OU EM BORRA DE CAFÉ.'),
    (124, 'MUITO URGENTE', 2, 2, 'EVACUAÇÃO DE SANGUE VIVO OU ESCURECIDO', 'EVIDÊNCIA DE SANGRAMENTO GASTRINTESTINAL ATIVO E/OU MACIÇO. PODERÁ HAVER EVACUAÇÃO DE SANGUE VERMELHO VIVO OU ESCURECIDO. QUANDO O TEMPO DO TRÂNSITO GASTRINTESTINAL AUMENTA, A EVACUAÇÃO SE TORNA PROGRESSIVAMENTE MAIS ESCURA ATÉ MELENA.'),
    (124, 'MUITO URGENTE', 2, 3, 'SANGRAMENTO VAGINAL COM 20 SEMANAS DE GRAVIDEZ OU MAIS', 'QUALQUER PERDA DE SANGUE PELA VAGINA EM MULHER SABIDAMENTE COM 20 SEMANAS DE GRAVIDEZ OU MAIS.'),
    (124, 'MUITO URGENTE', 2, 4, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (124, 'MUITO URGENTE', 2, 5, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (124, 'MUITO URGENTE', 2, 6, 'DOR EPIGÁSTRICA', 'DOR OU DESCONFORTO NO EPIGÁSTRIO ACOMPANHADA DE NÁUSEA, SUDORESE, SENSAÇÃO DE TONTEIRA.'),
    (124, 'MUITO URGENTE', 2, 7, 'DOR IRRADIADA PARA O DORSO', 'DOR QUE TAMBÉM É SENTIDA NO DORSO DE FORMA CONS­TANTE OU INTERMITENTE.'),
    (124, 'MUITO URGENTE', 2, 8, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (124, 'URGENTE', 3, 1, 'HISTÓRIA AGUDA DE VÔMITO DE SANGUE', 'QUALQUER RELATO DE HEMATÊMESE FRANCA, VÔMITO DE SANGUE ALTERADO (BORRA DE CAFÉ) OU SANGUE MISTURADO AO VÔMITO NAS ÚLTIMAS 24 HORAS PREENCHE ESTE CRITÉRIO.'),
    (124, 'URGENTE', 3, 2, 'FEZES PRETAS OU FEZES EM GROSELHA', 'QUALQUER RELATO DE FEZES ENEGRECIDAS PREENCHE ESTE CRITÉRIO. FEZES EM GROSELHA SÃO DE COLORAÇÃO VERMELHO ESCURO, CLASSICAMENTE VISTAS EM INTUSSUSCEPÇÃO. QUALQUER RELATO DESSES TIPOS DE FEZES PREENCHE ESTE CRITÉRIO.'),
    (124, 'URGENTE', 3, 3, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (124, 'URGENTE', 3, 4, 'GRAVIDEZ POSSÍVEL', 'QUALQUER MULHER CUJA MENSTRUAÇÃO NORMAL NÃO OCORREU ESTÁ POSSIVELMENTE GRÁVIDA. ALÉM DISSO, PARA QUALQUER MULHER EM IDADE FÉRTIL COM VIDA SEXUAL ATIVA SEM PROTEÇÃO DEVERÁ SER CONSIDERADA A POSSIBILIDADE DE GRAVIDEZ.'),
    (124, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (124, 'URGENTE', 3, 6, 'DOR IRRADIADA PARA O OMBRO', 'DOR SENTIDA NA PONTA DO OMBRO. GERALMENTE INDICA IRRITAÇÃO DIAFRAGMÁTICA.'),
    (124, 'URGENTE', 3, 7, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (124, 'POUCO URGENTE', 4, 1, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (124, 'POUCO URGENTE', 4, 2, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (124, 'POUCO URGENTE', 4, 3, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (125, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (125, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (125, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (125, 'MUITO URGENTE', 2, 1, 'VÔMITO DE SANGUE', 'EVIDÊNCIAS DE VÔMITO COM SANGUE. O SANGUE VOMITADO PODE SER FRESCO, RUTILANTE, ESCURECIDO OU EM BORRA DE CAFÉ.'),
    (125, 'MUITO URGENTE', 2, 2, 'EVACUAÇÃO DE SANGUE VIVO OU ESCURECIDO', 'EVIDÊNCIA DE SANGRAMENTO GASTRINTESTINAL ATIVO E/OU MACIÇO. PODERÁ HAVER EVACUAÇÃO DE SANGUE VERMELHO VIVO OU ESCURECIDO. QUANDO O TEMPO DO TRÂNSITO GASTRINTESTINAL AUMENTA, A EVACUAÇÃO SE TORNA PROGRESSIVAMENTE MAIS ESCURA ATÉ MELENA.'),
    (125, 'MUITO URGENTE', 2, 3, 'SANGRAMENTO VAGINAL COM 20 SEMANAS DE GRAVIDEZ OU MAIS', 'QUALQUER PERDA DE SANGUE PELA VAGINA EM MULHER SABIDAMENTE COM 20 SEMANAS DE GRAVIDEZ OU MAIS.'),
    (125, 'MUITO URGENTE', 2, 4, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (125, 'MUITO URGENTE', 2, 5, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (125, 'MUITO URGENTE', 2, 6, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (125, 'MUITO URGENTE', 2, 7, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (125, 'MUITO URGENTE', 2, 8, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (125, 'MUITO URGENTE', 2, 9, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (125, 'URGENTE', 3, 1, 'HISTÓRIA AGUDA DE VÔMITO DE SANGUE', 'QUALQUER RELATO DE HEMATÊMESE FRANCA, VÔMITO DE SANGUE ALTERADO (BORRA DE CAFÉ) OU SANGUE MISTURADO AO VÔMITO NAS ÚLTIMAS 24 HORAS PREENCHE ESTE CRITÉRIO.'),
    (125, 'URGENTE', 3, 2, 'FEZES PRETAS OU FEZES EM GROSELHA', 'QUALQUER RELATO DE FEZES ENEGRECIDAS PREENCHE ESTE CRITÉRIO. FEZES EM GROSELHA SÃO DE COLORAÇÃO VERMELHO ESCURO, CLASSICAMENTE VISTAS EM INTUSSUSCEPÇÃO. QUALQUER RELATO DESSES TIPOS DE FEZES PREENCHE ESTE CRITÉRIO.'),
    (125, 'URGENTE', 3, 3, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (125, 'URGENTE', 3, 4, 'GRAVIDEZ POSSÍVEL', 'QUALQUER MULHER CUJA MENSTRUAÇÃO NORMAL NÃO OCORREU ESTÁ POSSIVELMENTE GRÁVIDA. ALÉM DISSO, PARA QUALQUER MULHER EM IDADE FÉRTIL COM VIDA SEXUAL ATIVA SEM PROTEÇÃO DEVERÁ SER CONSIDERADA A POSSIBILIDADE DE GRAVIDEZ.'),
    (125, 'URGENTE', 3, 5, 'MASSA ABDOMINAL VISÍVEL', 'MASSA VISÍVEL À OBSERVAÇÃO DO ABDOME.'),
    (125, 'URGENTE', 3, 6, 'INCONSOLÁVEL PELOS PAIS', 'RELATO DE CHORO OU SOFRIMENTO, NÃO RESPONDEM ÀS TENTATIVAS DE ACALANTO DOS PAIS.'),
    (125, 'URGENTE', 3, 7, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (125, 'URGENTE', 3, 8, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (125, 'URGENTE', 3, 9, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (125, 'POUCO URGENTE', 4, 1, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (125, 'POUCO URGENTE', 4, 2, 'SINAIS DE DOR LEVE RECENTE', 'CRIANÇAS PEQUENAS E BEBÊS NÃO CONSEGUEM QUEIXAR. ELES PODEM CHORAR OCASIONALMENTE E PORTAR DE FORMA ATÍPICA.'),
    (125, 'POUCO URGENTE', 4, 3, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (126, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (126, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (126, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (126, 'MUITO URGENTE', 2, 1, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (126, 'MUITO URGENTE', 2, 2, 'SINAIS DE MENINGISMO', 'CLASSICAMENTE RIGIDEZ DE NUCA ASSOCIADA A CEFALEIA E FOTOFOBIA. EM CRIANÇAS PEQUENAS PODE HAVER IRRITABILIDADE À MANIPULAÇÃO, CHORO ESTRIDENTE E ABAULAMENTO DE FONTANELA.'),
    (126, 'MUITO URGENTE', 2, 3, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (126, 'MUITO URGENTE', 2, 4, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (126, 'MUITO URGENTE', 2, 5, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (126, 'MUITO URGENTE', 2, 6, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (126, 'MUITO URGENTE', 2, 7, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (126, 'MUITO URGENTE', 2, 8, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (126, 'URGENTE', 3, 1, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (126, 'URGENTE', 3, 2, 'TRAUMA DIRETO NO PESCOÇO', 'RELATO DE TRAUMA NO PESCOÇO E/OU NA CABEÇA POR CARGA QUE OCORREU DE CIMA PARA BAIXO. POR EXEMPLO: QUANDO ALGUMA COISA CAI NA CABEÇA CURVANDO-A PARA FRENTE, PARA TRÁS OU PARA O LADO OU PROVOCANDO UMA TORÇÃO.'),
    (126, 'URGENTE', 3, 3, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (126, 'URGENTE', 3, 4, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (126, 'URGENTE', 3, 5, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (126, 'POUCO URGENTE', 4, 1, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (126, 'POUCO URGENTE', 4, 2, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (126, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (126, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (127, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (127, 'EMERGÊNCIA', 1, 2, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (127, 'EMERGÊNCIA', 1, 3, 'BABA-SE', 'SALIVA SAINDO PELA BOCA POR INCAPACIDADE DE ENGOLIR.'),
    (127, 'EMERGÊNCIA', 1, 4, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (127, 'EMERGÊNCIA', 1, 5, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (127, 'EMERGÊNCIA', 1, 6, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (127, 'MUITO URGENTE', 2, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (127, 'MUITO URGENTE', 2, 2, 'IMUNOSSUPRESSÃO CONHECIDA OU PROVÁVEL', 'QUALQUER PACIENTE EM USO DE DROGAS IMUNOSSUPRESSORAS (INCLUINDO USO PROLONGADO DE CORTICOIDE) OU COM DOENÇA QUE CAUSE IMUNOSSUPRESSÃO.'),
    (127, 'MUITO URGENTE', 2, 3, 'RISCO ESPECIAL DE INFECÇÃO', 'EXPOSIÇÃO CONHECIDA A PATÓGENO DE ALTO RISCO, QUER EM LABORATÓRIO OU VIAGEM PARA REGIÃO DE PREVALÊNCIA CONHECIDA DE DOENÇA INFECCIOSA.'),
    (127, 'MUITO URGENTE', 2, 4, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (127, 'MUITO URGENTE', 2, 5, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (127, 'MUITO URGENTE', 2, 6, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (127, 'MUITO URGENTE', 2, 7, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (127, 'MUITO URGENTE', 2, 8, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (127, 'URGENTE', 3, 1, 'INÍCIO SÚBITO', 'INÍCIO NAS ÚLTIMAS 12 HORAS.'),
    (127, 'URGENTE', 3, 2, 'HISTÓRIA DE VIAGEM RECENTE', 'VIAGEM NAS DUAS ÚLTIMAS SEMANAS.'),
    (127, 'URGENTE', 3, 3, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (127, 'URGENTE', 3, 4, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (127, 'URGENTE', 3, 5, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (127, 'POUCO URGENTE', 4, 1, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (127, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (127, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (127, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (127, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (128, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (128, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (128, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (128, 'MUITO URGENTE', 2, 1, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (128, 'MUITO URGENTE', 2, 2, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (128, 'MUITO URGENTE', 2, 3, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (128, 'MUITO URGENTE', 2, 4, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (128, 'MUITO URGENTE', 2, 5, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (128, 'MUITO URGENTE', 2, 6, 'DOR ABDOMINAL', 'RELATO DE QUALQUER DOR SENTIDA NO ABDOME. SE IRRADIADA PARA O DORSO PODE INDICAR DISSECÇÃO DE AORTA; SE ASSOCIADA A SANGRAMENTO VAGINAL, PODE SUGERIR GRAVIDEZ ECTÓPICA OU ABORTAMENTO.'),
    (128, 'MUITO URGENTE', 2, 7, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (128, 'URGENTE', 3, 1, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (128, 'URGENTE', 3, 2, 'TRAUMA DIRETO NO DORSO', 'RELATO DE TRAUMA NO DORSO POR CARGA QUE OCORREU DE CIMA PARA BAIXO. POR EXEMPLO: QUANDO SE CAI DE PÉ OU QUANDO A CARGA PROVOCA INCLINAÇÃO PARA FRENTE, PARA TRÁS OU PARA O LADO OU UMA TORÇÃO.'),
    (128, 'URGENTE', 3, 3, 'INCAPAZ DE ANDAR', 'É IMPORTANTE DIFERENCIAR O PACIENTE QUE NÃO CONSEGUE CAMINHAR PELA DOR DAQUELE QUE REALMENTE NÃO CONSEGUE ANDAR. SÓ O ÚLTIMO PREENCHE TAL CRITÉRIO.'),
    (128, 'URGENTE', 3, 4, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (128, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (128, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (128, 'URGENTE', 3, 7, 'CÓLICAS', 'DORES INTERMITENTES (EM ONDAS) QUE TENDEM A MELHORAR OU PIORAR A CADA 20 MINUTOS.'),
    (128, 'URGENTE', 3, 8, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (128, 'POUCO URGENTE', 4, 1, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (128, 'POUCO URGENTE', 4, 2, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
