    (129, 'POUCO URGENTE', 4, 4, 'TRAUMA DE ESCROTO', 'QUALQUER TRAUMA RECENTE HÁ MENOS DE SETE DIAS ENVOLVENDO A BOLSA ESCROTAL.'),
    (129, 'POUCO URGENTE', 4, 5, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
