    (130, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (130, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (130, 'MUITO URGENTE', 2, 2, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (130, 'MUITO URGENTE', 2, 3, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (130, 'MUITO URGENTE', 2, 4, 'DOR PRECORDIAL OU CARDÍACA', 'DOR NO MEIO DO PEITO, GERALMENTE EM APERTO OU PESO, QUE PODE IRRADIAR PARA O BRAÇO ESQUERDO OU PESCOÇO. PODE-SE ASSOCIAR A SUDORESE, NÁUSEAS, SENSAÇÃO DE LIPOTIMIA E/OU DOR EPIGÁSTRICA.'),
    (130, 'MUITO URGENTE', 2, 5, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (130, 'MUITO URGENTE', 2, 6, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.');
INSERT INTO discriminadores (id_fluxograma, classificacao, prioridade, ordem, pergunta, explicacao) VALUES
    (130, 'MUITO URGENTE', 2, 7, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (130, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (130, 'URGENTE', 3, 2, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (130, 'URGENTE', 3, 3, 'HISTÓRIA CARDÍACA IMPORTANTE', 'UMA ARRITMIA RECORRENTE AMEAÇADORA DA VIDA OU UMA CARDIOPATIA PREVIAMENTE CONHECIDA QUE PODE SE DETERIORAR RAPIDAMENTE.'),
    (130, 'URGENTE', 3, 4, 'DOR PLEURÍTICA', 'DOR LOCALIZADA NO TÓRAX QUE PIORA COM RESPIRAÇÃO, TOSSE OU ESPIRRO. DOR VENTILATÓRIO-DEPENDENTE.'),
    (130, 'URGENTE', 3, 5, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (130, 'URGENTE', 3, 6, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (130, 'URGENTE', 3, 7, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (130, 'POUCO URGENTE', 4, 1, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (130, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (130, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (130, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (130, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (131, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (131, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (131, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (131, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (131, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (131, 'EMERGÊNCIA', 1, 6, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (131, 'MUITO URGENTE', 2, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA NÃO TOTALMENTE ATRIBUÍVEL AO ÁLCOOL', 'PACIENTE NÃO TOTALMENTE ALERTA, COM HISTÓRIA DE INGESTÃO ALCOÓLICA, MAS HÁ ALGUMA DÚVIDA DE OUTRAS CAUSAS DE DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA. ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW.'),
    (131, 'MUITO URGENTE', 2, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (131, 'MUITO URGENTE', 2, 3, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (131, 'MUITO URGENTE', 2, 4, 'HISTÓRIA INADEQUADA', 'SE NÃO ESTÁ CLARA E INEQUÍVOCA A HISTÓRIA DE INGESTÃO AGUDA DE ÁLCOOL E SE TRAUMA CRANIANO, INGESTÃO DE DROGAS, COMORBIDADES, ETC. NÃO PODEM SER DEFINITIVAMENTE EXCLUÍDOS.'),
    (131, 'MUITO URGENTE', 2, 5, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (131, 'URGENTE', 3, 1, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA TOTALMENTE ATRIBUÍVEL AO ÁLCOOL', 'PACIENTE NÃO TOTALMENTE ALERTA, COM HISTÓRIA CLARA DE INGESTÃO ALCOÓLICA, QUANDO OUTRAS CAUSAS DE ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA FORAM EXCLUÍDAS. ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW.'),
    (131, 'URGENTE', 3, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (131, 'URGENTE', 3, 3, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (131, 'URGENTE', 3, 4, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (131, 'URGENTE', 3, 5, 'HISTÓRIA DE TRAUMA CRANIOENCEFÁLICO', 'HISTÓRIA DE TRAUMA FÍSICO ENVOLVENDO A CABEÇA. GERALMENTE ISSO SERÁ RELATADO PELO PACIENTE, MAS SE ELE ESTEVE INCONSCIENTE, A HISTÓRIA DEVERÁ SER COLHIDA DE UMA TESTEMUNHA CONFIÁVEL.'),
    (131, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (131, 'POUCO URGENTE', 4, 1, 'TRAUMA RECENTE', 'QUALQUER TRAUMA OCORRIDO HÁ MENOS DE SETE DIAS.'),
    (131, 'POUCO URGENTE', 4, 2, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (132, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (132, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (132, 'EMERGÊNCIA', 1, 3, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (132, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (132, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (132, 'MUITO URGENTE', 2, 1, 'EDEMA DE LÍNGUA', 'INCHAÇO NA LÍNGUA DE QUALQUER INTENSIDADE.'),
    (132, 'MUITO URGENTE', 2, 2, 'EDEMA FACIAL', 'INCHAÇO DIFUSO NA FACE GERALMENTE ENVOLVENDO OS LÁBIOS.'),
    (132, 'MUITO URGENTE', 2, 3, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (132, 'MUITO URGENTE', 2, 4, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (132, 'MUITO URGENTE', 2, 5, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (132, 'MUITO URGENTE', 2, 6, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (132, 'MUITO URGENTE', 2, 7, 'HISTÓRIA ALÉRGICA IMPORTANTE', 'SENSIBILIDADE CONHECIDA COM REAÇÃO GRAVE (POR EXEMPLO: NOZES, CAMARÃO, PICADA DE ABELHA).'),
    (132, 'MUITO URGENTE', 2, 8, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (132, 'MUITO URGENTE', 2, 9, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (132, 'MUITO URGENTE', 2, 10, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (132, 'MUITO URGENTE', 2, 11, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (132, 'MUITO URGENTE', 2, 12, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (132, 'MUITO URGENTE', 2, 13, 'DOR OU COCEIRA INTENSA', 'COCEIRA INTOLERÁVEL.'),
    (132, 'URGENTE', 3, 1, 'ERUPÇÃO OU VESÍCULAS DISSEMINADAS', 'QUALQUER ERUPÇÃO, INCLUSIVE AS SECRETANTES OU BOLHOSAS, COBRINDO MAIS DE 10% DA SUPERFÍCIE CORPORAL.'),
    (132, 'URGENTE', 3, 2, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (132, 'URGENTE', 3, 3, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (132, 'URGENTE', 3, 4, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (132, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (132, 'URGENTE', 3, 6, 'DOR OU COCEIRA MODERADA', 'COCEIRA INTENSA, MAS SUPORTÁVEL.'),
    (132, 'POUCO URGENTE', 4, 1, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (132, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (132, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (132, 'POUCO URGENTE', 4, 4, 'DOR OU COCEIRA LEVE RECENTE', 'QUALQUER COCEIRA QUE OCORREU NOS ÚLTIMOS SETE DIAS.'),
    (132, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (133, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (133, 'EMERGÊNCIA', 1, 2, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (133, 'EMERGÊNCIA', 1, 3, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (133, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (133, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (133, 'EMERGÊNCIA', 1, 6, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (133, 'EMERGÊNCIA', 1, 7, 'LESÃO OCULAR QUÍMICA AGUDA', 'QUALQUER SUBSTÂNCIA QUE RESPINGA OU CAI NOS OLHOS NAS ÚLTIMAS 12 HORAS E CAUSA DOR, QUEIMAÇÃO, REDUÇÃO DA VISÃO OU QUALQUER OUTRO SINTOMA.'),
    (133, 'MUITO URGENTE', 2, 1, 'EDEMA DE LÍNGUA', 'INCHAÇO NA LÍNGUA DE QUALQUER INTENSIDADE.'),
    (133, 'MUITO URGENTE', 2, 2, 'EDEMA FACIAL', 'INCHAÇO DIFUSO NA FACE GERALMENTE ENVOLVENDO OS LÁBIOS.'),
    (133, 'MUITO URGENTE', 2, 3, 'LESÃO POR INALAÇÃO', 'HISTÓRIA DE CONFINAMENTO EM ESPAÇO COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE ASPIRAÇÃO DE FUMAÇA. FULIGEM EM TORNO DA BOCA E NARIZ, ALÉM DE ROUQUIDÃO, ESTARÁ PRESENTE. HISTÓRIA É TAMBÉM A FORMA MAIS SEGURA DE SE DIAGNOSTICAR INALAÇÃO DE AGENTES QUÍMICOS - PODE NÃO HAVER ALGUM OUTRO SINAL.'),
    (133, 'MUITO URGENTE', 2, 4, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (133, 'MUITO URGENTE', 2, 5, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (133, 'MUITO URGENTE', 2, 6, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (133, 'MUITO URGENTE', 2, 7, 'MORTALIDADE QUÍMICA ALTA', 'MORTALIDADE É O POTENCIAL DE UMA SUBSTÂNCIA QUÍMICA CAUSAR DANO. INTERCONSULTA EM UM CENTRO DE INTOXICAÇÕES PODE SER NECESSÁRIA PARA SE ESTABELECER O RISCO DE LESÃO OU MORTE. NA DÚVIDA, CONSIDERE ALTO O RISCO.'),
    (133, 'MUITO URGENTE', 2, 8, 'RISCO DE CONTAMINAÇÃO PERSISTENTE', 'DEVE SER CONSIDERADA SE A EXPOSIÇÃO QUÍMICA CONTINUAR (POR DESCONTAMINAÇÃO INADEQUADA). O RISCO DE CONTAMINAÇÃO DOS TRABALHADORES DE SAÚDE NÃO DEVE SER ESQUECIDO.'),
    (133, 'MUITO URGENTE', 2, 9, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (133, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (133, 'URGENTE', 3, 2, 'EXPOSIÇÃO À FUMAÇA', 'HISTÓRIA DE CONFINAMENTO EM LUGAR COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE EXPOSIÇÃO À FUMAÇA. PODE HAVER FULIGEM EM TORNO DA BOCA E NARIZ.'),
    (133, 'URGENTE', 3, 3, 'ERUPÇÃO OU VESÍCULAS DISSEMINADAS', 'QUALQUER ERUPÇÃO, INCLUSIVE AS SECRETANTES OU BOLHOSAS, COBRINDO MAIS DE 10% DA SUPERFÍCIE CORPORAL.'),
    (133, 'URGENTE', 3, 4, 'MORTALIDADE QUÍMICA MODERADA', 'MORTALIDADE É O POTENCIAL DE UMA SUBSTÂNCIA QUÍMICA CAUSAR DANO. INTERCONSULTA EM UM CENTRO DE INTOXICAÇÕES PODE SER NECESSÁRIA PARA SE ESTABELECER O RISCO DE LESÃO OU MORTE. NA DÚVIDA, CONSIDERE ESTE DISCRIMINADOR.'),
    (133, 'URGENTE', 3, 5, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (133, 'URGENTE', 3, 6, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (133, 'POUCO URGENTE', 4, 1, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (133, 'POUCO URGENTE', 4, 2, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (134, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (134, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (134, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (134, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (134, 'MUITO URGENTE', 2, 1, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (134, 'MUITO URGENTE', 2, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (134, 'MUITO URGENTE', 2, 3, 'COMPROMETIMENTO VASCULAR DISTAL', 'HAVERÁ ASSOCIAÇÃO DE PALIDEZ, ESFRIAMENTO, ALTERAÇÃO DA SENSIBILIDADE E/OU DOR COM OU SEM PULSO DISTAL À LESÃO.'),
    (134, 'MUITO URGENTE', 2, 4, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (134, 'MUITO URGENTE', 2, 5, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (134, 'MUITO URGENTE', 2, 6, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (134, 'MUITO URGENTE', 2, 7, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (134, 'MUITO URGENTE', 2, 8, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (134, 'MUITO URGENTE', 2, 9, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (134, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (134, 'URGENTE', 3, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (134, 'URGENTE', 3, 3, 'TRAUMA VAGINAL', 'QUALQUER HISTÓRIA OU OUTRA EVIDÊNCIA DE TRAUMA NA VAGINA.'),
    (134, 'URGENTE', 3, 4, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (134, 'URGENTE', 3, 5, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (134, 'URGENTE', 3, 6, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (134, 'URGENTE', 3, 7, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (134, 'URGENTE', 3, 8, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (134, 'POUCO URGENTE', 4, 1, 'INFLAMAÇÃO LOCAL', 'IMPLICA DOR, INCHAÇO E VERMELHIDÃO, RESTRITA A UMA ÁREA DEFINIDA.'),
    (134, 'POUCO URGENTE', 4, 2, 'INFECÇÃO LOCAL', 'MANIFESTA-SE GERALMENTE COMO INFLAMAÇÃO (DOR, INCHAÇO E VERMELHIDÃO) RESTRITA A UMA ÁREA DEFINIDA, COM OU SEM COLEÇÃO DE PUS.'),
    (134, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (134, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (135, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (135, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (135, 'EMERGÊNCIA', 1, 3, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (135, 'EMERGÊNCIA', 1, 4, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (135, 'EMERGÊNCIA', 1, 5, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (135, 'EMERGÊNCIA', 1, 6, 'PROLAPSO DE CORDÃO UMBILICAL', 'PROLAPSO DE QUALQUER PARTE DO CORDÃO UMBILICAL PELO CÉRVIX UTERINO DURANTE O TRABALHO DE PARTO.'),
    (135, 'EMERGÊNCIA', 1, 7, 'APRESENTAÇÃO DE PARTES FETAIS', 'APRESENTAÇÃO DA CABEÇA (COROAMENTO) OU DE QUALQUER OUTRA PARTE FETAL PELA VAGINA.'),
    (135, 'MUITO URGENTE', 2, 1, 'SANGRAMENTO VAGINAL INTENSO', 'ANGRAMENTO VAGINAL É MUITO DIFÍCIL DE QUANTIFICAÇÃO. EVIDÊNCIAS DE GRANDES PERDAS DE SANGUE PELA VAGINA OU FLUXO CONSTANTE PREENCHEM ESTE CRITÉRIO. GRANDES COÁGULOS PODEM SER OBSERVADOS. O USO DE GRANDE NÚMERO DE ABSORVENTES HIGIÊNICOS SUGERE PERDA INTENSA.'),
    (135, 'MUITO URGENTE', 2, 2, 'SANGRAMENTO VAGINAL COM 20 SEMANAS DE GRAVIDEZ OU MAIS', 'QUALQUER PERDA DE SANGUE PELA VAGINA EM MULHER SABIDAMENTE COM 20 SEMANAS DE GRAVIDEZ OU MAIS.'),
    (135, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (135, 'MUITO URGENTE', 2, 4, 'TRABALHO DE PARTO', 'GRÁVIDA QUE APRESENTA CONTRAÇÕES DOLOROSAS, FREQUENTES E REGULARES.'),
    (135, 'MUITO URGENTE', 2, 5, 'AUSÊNCIA OU REDUÇÃO DE MOVIMENTOS FETAIS HÁ MAIS DE 12 HORAS, COM 20 SEMANAS DE GRAVIDEZ OU MAIS', 'RELATO DE AUSÊNCIA OU REDUÇÃO DE MOVIMENTOS FETAIS HÁ MAIS DE 12 HORAS, COM 20 SEMANAS DE GRAVIDEZ OU MAIS.'),
    (135, 'MUITO URGENTE', 2, 6, 'PRESSÃO ARTERIAL MUITO ELEVADA', 'NÍVEIS TENSÓRICOS MUITO ELEVADOS. PRESSÃO ARTERIAL SISTÓLICA ELEVADA DE 160 MMHG OU MAIS E/OU PRESSÃO ARTERIAL DIASTÓLICA DE 110 MMHG OU MAIS.'),
    (135, 'MUITO URGENTE', 2, 7, 'RELATO DE PERDA DE LÍQUIDO PELA VAGINA, ESVERDEADO E ESPESSO', 'QUALQUER RELATO DE PERDA DE LÍQUIDO PELA VAGINA COM COLORAÇÃO ESVERDEADA E ESPESSO.'),
    (135, 'MUITO URGENTE', 2, 8, 'HISTÓRIA DE CONVULSÃO', 'QUALQUER HISTÓRIA DE CONVULSÃO, OBSERVADA OU RELATADA, QUE OCORREU NESSE PERÍODO DE DOENÇA OU APÓS TRAUMA. PARA GRAVIDEZ, SE HOUVE CONVULSÃO NAS 6 HORAS PRÉVIAS, PODE SIGNIFICAR ECLAMPSIA.'),
    (135, 'MUITO URGENTE', 2, 9, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (135, 'MUITO URGENTE', 2, 10, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (135, 'MUITO URGENTE', 2, 11, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (135, 'MUITO URGENTE', 2, 12, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (135, 'URGENTE', 3, 1, 'DOR ABDOMINAL', 'RELATO DE QUALQUER DOR SENTIDA NO ABDOME. SE IRRADIADA PARA O DORSO PODE INDICAR DISSECÇÃO DE AORTA; SE ASSOCIADA A SANGRAMENTO VAGINAL, PODE SUGERIR GRAVIDEZ ECTÓPICA OU ABORTAMENTO.'),
    (135, 'URGENTE', 3, 2, 'SANGRAMENTO VAGINAL', 'QUALQUER RELATO DE PERDA DE SANGUE PELA VAGINA.'),
    (135, 'URGENTE', 3, 3, 'PRESSÃO ARTERIAL ELEVADA', 'NÍVEIS TENSÓRICOS ELEVADOS. PRESSÃO ARTERIAL SISTÓLICA ELEVADA DE 140 MMHG OU MAIS E/OU PRESSÃO ARTERIAL DIASTÓLICA DE 90 MMHG OU MAIS.'),
    (135, 'URGENTE', 3, 4, 'AUSÊNCIA OU REDUÇÃO DE MOVIMENTOS FETAIS HÁ MENOS DE 12 HORAS, COM 20 SEMANAS DE GRAVIDEZ OU MAIS', 'RELATO DE AUSÊNCIA OU REDUÇÃO DE MOVIMENTOS FETAIS HÁ ME­NOS DE 12 HORAS, COM 20 SEMANAS DE GRAVIDEZ OU MAIS.'),
    (135, 'URGENTE', 3, 5, 'HISTÓRIA DE TRAUMA', 'HISTÓRIA RECENTE DE TRAUMA FÍSICO.'),
    (135, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (135, 'URGENTE', 3, 7, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (135, 'URGENTE', 3, 8, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (135, 'URGENTE', 3, 9, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (135, 'URGENTE', 3, 10, 'DOR IRRADIADA PARA O OMBRO', 'DOR SENTIDA NA PONTA DO OMBRO. GERALMENTE INDICA IRRITAÇÃO DIAFRAGMÁTICA.'),
    (135, 'URGENTE', 3, 11, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (135, 'POUCO URGENTE', 4, 1, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (135, 'POUCO URGENTE', 4, 2, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (135, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (135, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (136, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (136, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (136, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (136, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (136, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (136, 'MUITO URGENTE', 2, 1, 'VÔMITO DE SANGUE', 'EVIDÊNCIAS DE VÔMITO COM SANGUE. O SANGUE VOMITADO PODE SER FRESCO, RUTILANTE, ESCURECIDO OU EM BORRA DE CAFÉ.'),
    (136, 'MUITO URGENTE', 2, 2, 'EVACUAÇÃO DE SANGUE VIVO OU ESCURECIDO', 'EVIDÊNCIA DE SANGRAMENTO GASTRINTESTINAL ATIVO E/OU MACIÇO. PODERÁ HAVER EVACUAÇÃO DE SANGUE VERMELHO VIVO OU ESCURECIDO. QUANDO O TEMPO DO TRÂNSITO GASTRINTESTINAL AUMENTA, A EVACUAÇÃO SE TORNA PROGRESSIVAMENTE MAIS ESCURA ATÉ MELENA.'),
    (136, 'MUITO URGENTE', 2, 3, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (136, 'MUITO URGENTE', 2, 4, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (136, 'MUITO URGENTE', 2, 5, 'HISTÓRIA DE HEMORRAGIA DIGESTIVA IMPORTANTE', 'QUALQUER PASSADO DE SANGRAMENTO GASTRINTESTINAL MACIÇO OU ASSOCIADO A VARIZES ESOFAGIANAS.'),
    (136, 'MUITO URGENTE', 2, 6, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (136, 'MUITO URGENTE', 2, 7, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (136, 'URGENTE', 3, 1, 'HISTÓRIA AGUDA DE VÔMITO DE SANGUE', 'QUALQUER RELATO DE HEMATÊMESE FRANCA, VÔMITO DE SANGUE ALTERADO (BORRA DE CAFÉ) OU SANGUE MISTURADO AO VÔMITO NAS ÚLTIMAS 24 HORAS PREENCHE ESTE CRITÉRIO.'),
    (136, 'URGENTE', 3, 2, 'FEZES PRETAS OU FEZES EM GROSELHA', 'QUALQUER RELATO DE FEZES ENEGRECIDAS PREENCHE ESTE CRITÉRIO. FEZES EM GROSELHA SÃO DE COLORAÇÃO VERMELHO ESCURO, CLASSICAMENTE VISTAS EM INTUSSUSCEPÇÃO. QUALQUER RELATO DESSES TIPOS DE FEZES PREENCHE ESTE CRITÉRIO.'),
    (136, 'URGENTE', 3, 3, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (136, 'URGENTE', 3, 4, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (136, 'URGENTE', 3, 5, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (136, 'POUCO URGENTE', 4, 1, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (136, 'POUCO URGENTE', 4, 2, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (136, 'POUCO URGENTE', 4, 3, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (137, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (137, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (137, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (137, 'MUITO URGENTE', 2, 1, 'COMPROMETIMENTO VASCULAR DISTAL', 'HAVERÁ ASSOCIAÇÃO DE PALIDEZ, ESFRIAMENTO, ALTERAÇÃO DA SENSIBILIDADE E/OU DOR COM OU SEM PULSO DISTAL À LESÃO.'),
    (137, 'MUITO URGENTE', 2, 2, 'ENFISEMA SUBCUTÂNEO', 'GÁS DEBAIXO DA PELE QUE PODE SER DETECTADO POR SENSAÇÃO DE CREPITAÇÃO AO TOQUE. PODE HAVER BOLHAS DE GÁS E LINHA DE DEMARCAÇÃO.'),
    (137, 'MUITO URGENTE', 2, 3, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (137, 'MUITO URGENTE', 2, 4, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (137, 'MUITO URGENTE', 2, 5, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (137, 'MUITO URGENTE', 2, 6, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (137, 'MUITO URGENTE', 2, 7, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (137, 'MUITO URGENTE', 2, 8, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (137, 'URGENTE', 3, 1, 'ARTICULAÇÃO QUENTE', 'QUALQUER AUMENTO DA TEMPERATURA EM TORNO DA ARTICULAÇÃO PREENCHE ESTE CRITÉRIO. GERALMENTE ESTÁ ASSOCIADA À VERMELHIDÃO.'),
    (137, 'URGENTE', 3, 2, 'DOR AO MOVIMENTO ARTICULAR', 'A DOR PODE OCORRER TANTO NA MOVIMENTAÇÃO ATIVA (DO PACIENTE) COMO PASSIVA (PELO EXAMINADOR) DA ARTICULAÇÃO.'),
    (137, 'URGENTE', 3, 3, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (137, 'URGENTE', 3, 4, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (137, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (137, 'URGENTE', 3, 6, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (137, 'POUCO URGENTE', 4, 1, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (137, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (137, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (137, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (137, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (138, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (138, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (138, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (138, 'EMERGÊNCIA', 1, 4, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (138, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (138, 'MUITO URGENTE', 2, 1, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (138, 'MUITO URGENTE', 2, 2, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (138, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (138, 'MUITO URGENTE', 2, 4, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (138, 'MUITO URGENTE', 2, 5, 'SINAIS DE MENINGISMO', 'CLASSICAMENTE RIGIDEZ DE NUCA ASSOCIADA A CEFALEIA E FOTOFOBIA. EM CRIANÇAS PEQUENAS PODE HAVER IRRITABILIDADE À MANIPULAÇÃO, CHORO ESTRIDENTE E ABAULAMENTO DE FONTANELA.'),
    (138, 'MUITO URGENTE', 2, 6, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (138, 'MUITO URGENTE', 2, 7, 'HEMOPTISE', 'SANGUE AERADO EMITIDO COM O ESFORÇO DA TOSSE OBSERVADO PELO CLASSIFICADOR.'),
    (138, 'MUITO URGENTE', 2, 8, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (138, 'MUITO URGENTE', 2, 9, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.');
INSERT INTO discriminadores (id_fluxograma, classificacao, prioridade, ordem, pergunta, explicacao) VALUES
    (138, 'MUITO URGENTE', 2, 10, 'IMUNOSSUPRESSÃO CONHECIDA OU PROVÁVEL', 'QUALQUER PACIENTE EM USO DE DROGAS IMUNOSSUPRESSORAS (INCLUINDO USO PROLONGADO DE CORTICOIDE) OU COM DOENÇA QUE CAUSE IMUNOSSUPRESSÃO.'),
    (138, 'MUITO URGENTE', 2, 11, 'RISCO ESPECIAL DE INFECÇÃO', 'EXPOSIÇÃO CONHECIDA A PATÓGENO DE ALTO RISCO, QUER EM LABORATÓRIO OU VIAGEM PARA REGIÃO DE PREVALÊNCIA CONHECIDA DE DOENÇA INFECCIOSA.'),
    (138, 'MUITO URGENTE', 2, 12, 'DOR EPIGÁSTRICA', 'DOR OU DESCONFORTO NO EPIGÁSTRIO ACOMPANHADA DE NÁUSEA, SUDORESE, SENSAÇÃO DE TONTEIRA.'),
    (138, 'MUITO URGENTE', 2, 13, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (138, 'MUITO URGENTE', 2, 14, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (138, 'MUITO URGENTE', 2, 15, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (138, 'MUITO URGENTE', 2, 16, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (138, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (138, 'URGENTE', 3, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (138, 'URGENTE', 3, 3, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (138, 'URGENTE', 3, 4, 'HISTÓRIA DE HEMOPTISE', 'QUALQUER RELATO DE SANGUE AERADO EMITIDO COM O ESFORÇO DA TOSSE PREENCHE ESTE CRITÉRIO.'),
    (138, 'URGENTE', 3, 5, 'ERUPÇÃO OU VESÍCULAS DISSEMINADAS', 'QUALQUER ERUPÇÃO, INCLUSIVE AS SECRETANTES OU BOLHOSAS, COBRINDO MAIS DE 10% DA SUPERFÍCIE CORPORAL.'),
    (138, 'URGENTE', 3, 6, 'INÍCIO SÚBITO', 'INÍCIO NAS ÚLTIMAS 12 HORAS.'),
    (138, 'URGENTE', 3, 7, 'HISTÓRIA DE VIAGEM RECENTE', 'VIAGEM NAS DUAS ÚLTIMAS SEMANAS.'),
    (138, 'URGENTE', 3, 8, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (138, 'URGENTE', 3, 9, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (138, 'URGENTE', 3, 10, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (138, 'POUCO URGENTE', 4, 1, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (138, 'POUCO URGENTE', 4, 2, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (138, 'POUCO URGENTE', 4, 3, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (139, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (139, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (139, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (139, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (139, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (139, 'EMERGÊNCIA', 1, 6, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (139, 'MUITO URGENTE', 2, 1, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (139, 'MUITO URGENTE', 2, 2, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (139, 'MUITO URGENTE', 2, 3, 'RESPOSTA À VOZ OU À DOR APENAS', 'RESPOSTA A ESTÍMULOS DOLOROSOS. O ESTÍMULO PERIFÉRICO PADRÃO DEVE SER REALIZADO PRESSIONANDO UMA CANETA NO LEITO UNGUEAL DOS DEDOS DAS MÃOS. ESTE TIPO DE ESTÍMULO NÃO DEVE SER FEITO NO HÁLUX, POIS O REFLEXO ESPINHAL PODE CAUSAR FLEXÃO MESMO NA MORTE ENCEFÁLICA. PRESSÃO SUPRAORBITÁRIA TAMBÉM NÃO DEVE SER UTILIZADA, POIS PODE PRODUZIR O REFLEXO DE CONTORÇÃO DE FACE. RESPOSTA AO ESTÍMULO DA VOZ. NÃO É NECESSÁRIO GRITAR O NOME DO PACIENTE. CRIANÇAS PODEM NÃO RESPONDER, POR ESTAREM COM MEDO.'),
    (139, 'MUITO URGENTE', 2, 4, 'NÃO REAGE AOS PAIS', 'NÃO REAGE DE FORMA ALGUMA AO ROSTO OU À VOZ DOS PAIS. REAÇÕES ANORMAIS E APARENTE PERDA DE RECONHECIMENTO DOS PAIS TAMBÉM SÃO SINAIS PREOCUPANTES.'),
    (139, 'MUITO URGENTE', 2, 5, 'SINAIS DE MENINGISMO', 'CLASSICAMENTE RIGIDEZ DE NUCA ASSOCIADA A CEFALEIA E FOTOFOBIA. EM CRIANÇAS PEQUENAS PODE HAVER IRRITABILIDADE À MANIPULAÇÃO, CHORO ESTRIDENTE E ABAULAMENTO DE FONTANELA.'),
    (139, 'MUITO URGENTE', 2, 6, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (139, 'MUITO URGENTE', 2, 7, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (139, 'MUITO URGENTE', 2, 8, 'IMUNOSSUPRESSÃO CONHECIDA OU PROVÁVEL', 'QUALQUER PACIENTE EM USO DE DROGAS IMUNOSSUPRESSORAS (INCLUINDO USO PROLONGADO DE CORTICOIDE) OU COM DOENÇA QUE CAUSE IMUNOSSUPRESSÃO.'),
    (139, 'MUITO URGENTE', 2, 9, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (139, 'MUITO URGENTE', 2, 10, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (139, 'MUITO URGENTE', 2, 11, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (139, 'MUITO URGENTE', 2, 12, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (139, 'MUITO URGENTE', 2, 13, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (139, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (139, 'URGENTE', 3, 2, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (139, 'URGENTE', 3, 3, 'SINAIS DE DESIDRATAÇÃO', 'LÍNGUA SECA, ENOFTALMIA (OLHOS FUNDOS), TURGOR PASTOSO E, EM BEBÊS PEQUENOS, FONTANELA BAIXA. GERALMENTE, HÁ OLIGÚRIA (DIMINUIÇÃO DA DIURESE).'),
    (139, 'URGENTE', 3, 4, 'NÃO SE ALIMENTA', 'CRIANÇA QUE NÃO INGERE NADA SÓLIDO OU LÍQUIDO COMO DE HÁBITO. CRIANÇA QUE SE ALIMENTA, MAS VOMITA LOGO APÓS TAMBÉM PREENCHE ESTE CRITÉRIO.'),
    (139, 'URGENTE', 3, 5, 'SEM URINAR', 'DIFICULDADE EM PRODUZIR OU ELIMINAR URINA. PODE SER DIFÍCIL SUA AVALIAÇÃO EM CRIANÇAS E IDOSOS. O RELATO DO NÚMERO DE FRALDAS TROCADAS PODE SER ÚTIL.'),
    (139, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (139, 'URGENTE', 3, 7, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (139, 'URGENTE', 3, 8, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (139, 'POUCO URGENTE', 4, 1, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (139, 'POUCO URGENTE', 4, 2, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (139, 'POUCO URGENTE', 4, 3, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (140, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
