    (140, 'MUITO URGENTE', 2, 8, 'IMUNOSSUPRESSÃO CONHECIDA OU PROVÁVEL', 'QUALQUER PACIENTE EM USO DE DROGAS IMUNOSSUPRESSORAS (INCLUINDO USO PROLONGADO DE CORTICOIDE) OU COM DOENÇA QUE CAUSE IMUNOSSUPRESSÃO.'),
    (140, 'MUITO URGENTE', 2, 9, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (140, 'MUITO URGENTE', 2, 10, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (140, 'MUITO URGENTE', 2, 11, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (140, 'MUITO URGENTE', 2, 12, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (140, 'MUITO URGENTE', 2, 13, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (140, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (140, 'URGENTE', 3, 2, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (140, 'URGENTE', 3, 3, 'SINAIS DE DESIDRATAÇÃO', 'LÍNGUA SECA, ENOFTALMIA (OLHOS FUNDOS), TURGOR PASTOSO E, EM BEBÊS PEQUENOS, FONTANELA BAIXA. GERALMENTE, HÁ OLIGÚRIA (DIMINUIÇÃO DA DIURESE).'),
    (140, 'URGENTE', 3, 4, 'NÃO SE ALIMENTA', 'CRIANÇA QUE NÃO INGERE NADA SÓLIDO OU LÍQUIDO COMO DE HÁBITO. CRIANÇA QUE SE ALIMENTA, MAS VOMITA LOGO APÓS TAMBÉM PREENCHE ESTE CRITÉRIO.'),
    (140, 'URGENTE', 3, 5, 'SEM URINAR', 'DIFICULDADE EM PRODUZIR OU ELIMINAR URINA. PODE SER DIFÍCIL SUA AVALIAÇÃO EM CRIANÇAS E IDOSOS. O RELATO DO NÚMERO DE FRALDAS TROCADAS PODE SER ÚTIL.'),
    (140, 'URGENTE', 3, 6, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (140, 'URGENTE', 3, 7, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (140, 'URGENTE', 3, 8, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (140, 'URGENTE', 3, 9, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (140, 'POUCO URGENTE', 4, 1, 'COMPORTAMENTO ATÍPICO', 'CRIANÇA COM COMPORTAMENTO NÃO HABITUAL EM DADA SITUAÇÃO. OS CUIDADORES FREQUENTEMENTE FORNECEM ESTA INFORMAÇÃO ESPONTANEAMENTE. A CRIANÇA PODE ESTAR RABUGENTA, INDÓCIL, IRRITADIÇA OU COM COMPORTAMENTO DIFERENTE DO SEU HABITUAL.'),
    (140, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (140, 'POUCO URGENTE', 4, 3, 'SINAIS DE DOR LEVE RECENTE', 'CRIANÇAS PEQUENAS E BEBÊS NÃO CONSEGUEM QUEIXAR. ELES PODEM CHORAR OCASIONALMENTE E PORTAR DE FORMA ATÍPICA.'),
    (140, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (141, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (141, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (141, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (141, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (141, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (141, 'EMERGÊNCIA', 1, 6, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (141, 'MUITO URGENTE', 2, 1, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (141, 'MUITO URGENTE', 2, 2, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (141, 'MUITO URGENTE', 2, 3, 'RESPOSTA À VOZ OU À DOR APENAS', 'RESPOSTA A ESTÍMULOS DOLOROSOS. O ESTÍMULO PERIFÉRICO PADRÃO DEVE SER REALIZADO PRESSIONANDO UMA CANETA NO LEITO UNGUEAL DOS DEDOS DAS MÃOS. ESTE TIPO DE ESTÍMULO NÃO DEVE SER FEITO NO HÁLUX, POIS O REFLEXO ESPINHAL PODE CAUSAR FLEXÃO MESMO NA MORTE ENCEFÁLICA. PRESSÃO SUPRAORBITÁRIA TAMBÉM NÃO DEVE SER UTILIZADA, POIS PODE PRODUZIR O REFLEXO DE CONTORÇÃO DE FACE. RESPOSTA AO ESTÍMULO DA VOZ. NÃO É NECESSÁRIO GRITAR O NOME DO PACIENTE. CRIANÇAS PODEM NÃO RESPONDER, POR ESTAREM COM MEDO.'),
    (141, 'MUITO URGENTE', 2, 4, 'NÃO REAGE AOS PAIS', 'NÃO REAGE DE FORMA ALGUMA AO ROSTO OU À VOZ DOS PAIS. REAÇÕES ANORMAIS E APARENTE PERDA DE RECONHECIMENTO DOS PAIS TAMBÉM SÃO SINAIS PREOCUPANTES.'),
    (141, 'MUITO URGENTE', 2, 5, 'SINAIS DE MENINGISMO', 'CLASSICAMENTE RIGIDEZ DE NUCA ASSOCIADA A CEFALEIA E FOTOFOBIA. EM CRIANÇAS PEQUENAS PODE HAVER IRRITABILIDADE À MANIPULAÇÃO, CHORO ESTRIDENTE E ABAULAMENTO DE FONTANELA.'),
    (141, 'MUITO URGENTE', 2, 6, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (141, 'MUITO URGENTE', 2, 7, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (141, 'MUITO URGENTE', 2, 8, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (141, 'MUITO URGENTE', 2, 9, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (141, 'MUITO URGENTE', 2, 10, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (141, 'MUITO URGENTE', 2, 11, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (141, 'MUITO URGENTE', 2, 12, 'SINAIS DE DOR INTENSA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR INTENSA NÃO CONSEGUEM SE QUEIXAR. ELES VÃO GRITAR E/OU CHORAR DE FORMA CONTÍNUA E INCONSOLÁVEL E GERALMENTE ESTARÃO TAQUICÁRDICOS. PODEM TAMBÉM APRESENTAR SINAIS COMO PALIDEZ E SUDORESE.'),
    (141, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (141, 'URGENTE', 3, 2, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (141, 'URGENTE', 3, 3, 'SINAIS DE DESIDRATAÇÃO', 'LÍNGUA SECA, ENOFTALMIA (OLHOS FUNDOS), TURGOR PASTOSO E, EM BEBÊS PEQUENOS, FONTANELA BAIXA. GERALMENTE, HÁ OLIGÚRIA (DIMINUIÇÃO DA DIURESE).'),
    (141, 'URGENTE', 3, 4, 'NÃO SE ALIMENTA', 'CRIANÇA QUE NÃO INGERE NADA SÓLIDO OU LÍQUIDO COMO DE HÁBITO. CRIANÇA QUE SE ALIMENTA, MAS VOMITA LOGO APÓS TAMBÉM PREENCHE ESTE CRITÉRIO.'),
    (141, 'URGENTE', 3, 5, 'SEM URINAR', 'DIFICULDADE EM PRODUZIR OU ELIMINAR URINA. PODE SER DIFÍCIL SUA AVALIAÇÃO EM CRIANÇAS E IDOSOS. O RELATO DO NÚMERO DE FRALDAS TROCADAS PODE SER ÚTIL.'),
    (141, 'URGENTE', 3, 6, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (141, 'URGENTE', 3, 7, 'ICTERÍCIA', 'ICTERÍCIA NEONATAL.'),
    (141, 'URGENTE', 3, 8, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (141, 'URGENTE', 3, 9, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (141, 'URGENTE', 3, 10, 'SINAIS DE DOR MODERADA', 'CRIANÇAS PEQUENAS E BEBÊS COM DOR MODERADA NÃO CONSEGUEM QUEIXAR. ELES GERALMENTE CHORAM INTERMITENTEMENTE E SÃO OCASIONALMENTE CONSOLÁVEIS.'),
    (141, 'POUCO URGENTE', 4, 1, 'SINAIS DE DOR LEVE RECENTE', 'CRIANÇAS PEQUENAS E BEBÊS NÃO CONSEGUEM QUEIXAR. ELES PODEM CHORAR OCASIONALMENTE E PORTAR DE FORMA ATÍPICA.'),
    (141, 'POUCO URGENTE', 4, 2, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (142, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (142, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (142, 'EMERGÊNCIA', 1, 3, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (142, 'EMERGÊNCIA', 1, 4, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (142, 'EMERGÊNCIA', 1, 5, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (142, 'EMERGÊNCIA', 1, 6, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (142, 'MUITO URGENTE', 2, 1, 'EDEMA FACIAL', 'INCHAÇO DIFUSO NA FACE GERALMENTE ENVOLVENDO OS LÁBIOS.'),
    (142, 'MUITO URGENTE', 2, 2, 'EDEMA DE LÍNGUA', 'INCHAÇO NA LÍNGUA DE QUALQUER INTENSIDADE.'),
    (142, 'MUITO URGENTE', 2, 3, 'FRASES ENTRECORTADAS', 'DOENTES COM DIFICULDADE RESPIRATÓRIA TÃO GRANDE QUE NÃO CONSEGUEM NEM ARTICULAR FRASES CURTAS NUMA SÓ RESPIRAÇÃO.'),
    (142, 'MUITO URGENTE', 2, 4, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (142, 'MUITO URGENTE', 2, 5, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (142, 'MUITO URGENTE', 2, 6, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (142, 'MUITO URGENTE', 2, 7, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (142, 'MUITO URGENTE', 2, 8, 'ENVENENAMENTO DE ALTA MORTALIDADE', 'ALTA POTÊNCIA DO VENENO CAUSAR DANO. CONHECIMENTO REGIONAL PODE AJUDAR A IDENTIFICAR O ANIMAL PEÇONHENTO. INTERCONSULTA COM UM CENTRO DE TOXICOLOGIA PODE SER NECESSÁRIA. NA DÚVIDA, DEFINIR COMO ALTO O RISCO.'),
    (142, 'MUITO URGENTE', 2, 9, 'HISTÓRIA ALÉRGICA IMPORTANTE', 'SENSIBILIDADE CONHECIDA COM REAÇÃO GRAVE (POR EXEMPLO: NOZES, CAMARÃO, PICADA DE ABELHA).'),
    (142, 'MUITO URGENTE', 2, 10, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (142, 'MUITO URGENTE', 2, 11, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (142, 'MUITO URGENTE', 2, 12, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (142, 'MUITO URGENTE', 2, 13, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (142, 'MUITO URGENTE', 2, 14, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (142, 'MUITO URGENTE', 2, 15, 'DOR OU COCEIRA INTENSA', 'COCEIRA INTOLERÁVEL.'),
    (142, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (142, 'URGENTE', 3, 2, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (142, 'URGENTE', 3, 3, 'ENVENENAMENTO DE MODERADA MORTALIDADE', 'MODERADA POTÊNCIA DO VENENO CAUSAR DANO. CONHECIMENTO REGIONAL PODE AJUDAR A IDENTIFICAR O ANIMAL PEÇONHENTO. INTERCONSULTA COM UM CENTRO DE TOXICOLOGIA PODE SER NECESSÁRIA.'),
    (142, 'URGENTE', 3, 4, 'ERUPÇÃO OU VESÍCULAS DISSEMINADAS', 'QUALQUER ERUPÇÃO, INCLUSIVE AS SECRETANTES OU BOLHOSAS, COBRINDO MAIS DE 10% DA SUPERFÍCIE CORPORAL.'),
    (142, 'URGENTE', 3, 5, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (142, 'URGENTE', 3, 6, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (142, 'URGENTE', 3, 7, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (142, 'URGENTE', 3, 8, 'DOR OU COCEIRA MODERADA', 'COCEIRA INTENSA, MAS SUPORTÁVEL.'),
    (142, 'POUCO URGENTE', 4, 1, 'INFLAMAÇÃO LOCAL', 'IMPLICA DOR, INCHAÇO E VERMELHIDÃO, RESTRITA A UMA ÁREA DEFINIDA.'),
    (142, 'POUCO URGENTE', 4, 2, 'INFECÇÃO LOCAL', 'MANIFESTA-SE GERALMENTE COMO INFLAMAÇÃO (DOR, INCHAÇO E VERMELHIDÃO) RESTRITA A UMA ÁREA DEFINIDA, COM OU SEM COLEÇÃO DE PUS.'),
    (142, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (142, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (143, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (143, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (143, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (143, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (143, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (143, 'EMERGÊNCIA', 1, 6, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (143, 'MUITO URGENTE', 2, 1, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (143, 'MUITO URGENTE', 2, 2, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (143, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (143, 'MUITO URGENTE', 2, 4, 'MORTALIDADE ALTA', 'LETALIDADE É O POTENCIAL DE UMA SUBSTÂNCIA INGERIDA OU INALADA CAUSAR DANO. ALTA PROBABILIDADE DA SUBSTÂNCIA À QUAL A VÍTIMA FOI EXPOSTA CAUSAR DOENÇA GRAVE OU MORTE. INTERCONSULTA EM UM CENTRO DE INTOXICAÇÕES PODE SER NECESSÁRIA PARA SE ESTABELECER O RISCO DE LESÃO OU MORTE. NA DÚVIDA, CONSIDERE ALTO RISCO.'),
    (143, 'MUITO URGENTE', 2, 5, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (143, 'MUITO URGENTE', 2, 6, 'ALTO RISCO DE AUTOAGRESSÃO', 'UMA AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE QUE TEM PASSADO IMPORTANTE DE  AUTOAGRESSÃO E ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR OU ESTÁ TENTANDO IR EMBORA PARA TAL FINALIDADE É DE ALTO RISCO.'),
    (143, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (143, 'URGENTE', 3, 2, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (143, 'URGENTE', 3, 3, 'AGITAÇÃO PSICOMOTORA', 'PACIENTE QUE ESTÁ FÍSICO E/OU EMOCIONALMENTE MUITO PERTURBADO (ANGÚSTIA PERCEPTÍVEL).'),
    (143, 'URGENTE', 3, 4, 'MORTALIDADE MODERADA', 'LETALIDADE É O POTENCIAL DE UMA SUBSTÂNCIA INGERIDA OU INALADA CAUSAR DANO. MODERADA PROBABILIDADE DA SUBSTÂNCIA À QUAL A VÍTIMA FOI EXPOSTA CAUSAR DOENÇA GRAVE OU MORTE. INTERCONSULTA EM UM CENTRO DE INTOXICAÇÕES PODE SER NECESSÁRIA PARA SE ESTABELECER O RISCO DE LESÃO OU MORTE.'),
    (143, 'URGENTE', 3, 5, 'RISCO MODERADO DE AUTOAGRESSÃO', 'AVALIAÇÃO INICIAL DO RISCO DE AUTOAGRESSÃO PODE SER FEITA PELO COMPORTAMENTO DO PACIENTE. AQUELE SEM PASSADO IMPORTANTE DE AUTOAGRESSÃO, QUE NÃO ESTÁ ATIVAMENTE TENTANDO SE MACHUCAR NEM TENTANDO IR EMBORA PARA TAL, MAS MANIFESTA DESEJO DE SE MACHUCAR, ESTÁ EM RISCO MODERADO.'),
    (143, 'URGENTE', 3, 6, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (143, 'URGENTE', 3, 7, 'HISTÓRIA PSIQUIÁTRICA IMPORTANTE', 'HISTÓRIA DE EVENTO OU DOENÇA PSIQUIÁTRICA SIGNIFICATIVA.'),
    (143, 'URGENTE', 3, 8, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (144, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (144, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (144, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (144, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (144, 'MUITO URGENTE', 2, 1, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (144, 'MUITO URGENTE', 2, 2, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (144, 'MUITO URGENTE', 2, 3, 'PROSTRAÇÃO, HIPOTONIA', 'PAIS DESCREVEM A CRIANÇA COMO "MOLINHA¿. O TÔNUS GERALMENTE ESTÁ DIMINUÍDO (O SINAL MAIS CARACTERÍSTICO É A CABEÇA CAÍDA).'),
    (144, 'MUITO URGENTE', 2, 4, 'RESPOSTA À VOZ OU À DOR APENAS', 'RESPOSTA A ESTÍMULOS DOLOROSOS. O ESTÍMULO PERIFÉRICO PADRÃO DEVE SER REALIZADO PRESSIONANDO UMA CANETA NO LEITO UNGUEAL DOS DEDOS DAS MÃOS. ESTE TIPO DE ESTÍMULO NÃO DEVE SER FEITO NO HÁLUX, POIS O REFLEXO ESPINHAL PODE CAUSAR FLEXÃO MESMO NA MORTE ENCEFÁLICA. PRESSÃO SUPRAORBITÁRIA TAMBÉM NÃO DEVE SER UTILIZADA, POIS PODE PRODUZIR O REFLEXO DE CONTORÇÃO DE FACE. RESPOSTA AO ESTÍMULO DA VOZ. NÃO É NECESSÁRIO GRITAR O NOME DO PACIENTE. CRIANÇAS PODEM NÃO RESPONDER, POR ESTAREM COM MEDO.'),
    (144, 'MUITO URGENTE', 2, 5, 'NÃO REAGE AOS PAIS', 'NÃO REAGE DE FORMA ALGUMA AO ROSTO OU À VOZ DOS PAIS. REAÇÕES ANORMAIS E APARENTE PERDA DE RECONHECIMENTO DOS PAIS TAMBÉM SÃO SINAIS PREOCUPANTES.'),
    (144, 'MUITO URGENTE', 2, 6, 'PÚRPURA', 'ERUPÇÃO DE QUALQUER PARTE DO CORPO QUE É CAUSADA POR PEQUENAS HEMORRAGIAS DEBAIXO DA PELE. ERUPÇÃO PURPÚRICA NÃO EMPALIDECE QUANDO PRESSÃO É APLICADA SOBRE ELA.'),
    (144, 'MUITO URGENTE', 2, 7, 'ERUPÇÃO CUTÂNEA FIXA', 'ERUPÇÃO QUE NÃO SE EMPALIDECE (SE TORNA BRANCA) QUANDO PRESSÃO É APLICADA SOBRE ELA. PODE SER TESTADA USANDO-SE UM COPO PARA PRESSIONAR A LESÃO. NÃO SE OBSERVA ALTERAÇÃO DA COLORAÇÃO ATRAVÉS DO FUNDO DO COPO.'),
    (144, 'MUITO URGENTE', 2, 8, 'HISTÓRIA DE OVERDOSE OU ENVENENAMENTO', 'ESTA INFORMAÇÃO PODE VIR DE OUTROS OU PODE SER DEDUZIDA NA PRESENÇA DE CAIXAS DE REMÉDIOS VAZIAS, ENTRE OUTRAS.'),
    (144, 'MUITO URGENTE', 2, 9, 'INGESTÃO DE OBJETO PERIGOSO', 'INGESTÃO DE OBJETO PERIGOSO OU POTENCIALMENTE PERIGOSO QUE POSSA AMEAÇAR A VIDA COMO POR EXEMPLO: BATERIA, IMÃ, LÂMINAS.'),
    (144, 'MUITO URGENTE', 2, 10, 'IMUNOSSUPRESSÃO CONHECIDA OU PROVÁVEL', 'QUALQUER PACIENTE EM USO DE DROGAS IMUNOSSUPRESSORAS (INCLUINDO USO PROLONGADO DE CORTICOIDE) OU COM DOENÇA QUE CAUSE IMUNOSSUPRESSÃO.'),
    (144, 'MUITO URGENTE', 2, 11, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (144, 'MUITO URGENTE', 2, 12, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (144, 'MUITO URGENTE', 2, 13, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (144, 'MUITO URGENTE', 2, 14, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (144, 'MUITO URGENTE', 2, 15, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (144, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (144, 'URGENTE', 3, 2, 'SINAIS DE DESIDRATAÇÃO', 'LÍNGUA SECA, ENOFTALMIA (OLHOS FUNDOS), TURGOR PASTOSO E, EM BEBÊS PEQUENOS, FONTANELA BAIXA. GERALMENTE, HÁ OLIGÚRIA (DIMINUIÇÃO DA DIURESE).'),
    (144, 'URGENTE', 3, 3, 'NÃO SE ALIMENTA', 'CRIANÇA QUE NÃO INGERE NADA SÓLIDO OU LÍQUIDO COMO DE HÁBITO. CRIANÇA QUE SE ALIMENTA, MAS VOMITA LOGO APÓS TAMBÉM PREENCHE ESTE CRITÉRIO.'),
    (144, 'URGENTE', 3, 4, 'SEM URINAR', 'DIFICULDADE EM PRODUZIR OU ELIMINAR URINA. PODE SER DIFÍCIL SUA AVALIAÇÃO EM CRIANÇAS E IDOSOS. O RELATO DO NÚMERO DE FRALDAS TROCADAS PODE SER ÚTIL.'),
    (144, 'URGENTE', 3, 5, 'INCONSOLÁVEL PELOS PAIS', 'RELATO DE CHORO OU SOFRIMENTO, NÃO RESPONDEM ÀS TENTATIVAS DE ACALANTO DOS PAIS.'),
    (144, 'URGENTE', 3, 6, 'CHORO PROLONGADO OU ININTERRUPTO', 'RELATO DE CHORO CONTÍNUO POR 2 HORAS OU MAIS.'),
    (144, 'URGENTE', 3, 7, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (144, 'URGENTE', 3, 8, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (144, 'URGENTE', 3, 9, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (144, 'URGENTE', 3, 10, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (144, 'POUCO URGENTE', 4, 1, 'COMPORTAMENTO ATÍPICO', 'CRIANÇA COM COMPORTAMENTO NÃO HABITUAL EM DADA SITUAÇÃO. OS CUIDADORES FREQUENTEMENTE FORNECEM ESTA INFORMAÇÃO ESPONTANEAMENTE. A CRIANÇA PODE ESTAR RABUGENTA, INDÓCIL, IRRITADIÇA OU COM COMPORTAMENTO DIFERENTE DO SEU HABITUAL.'),
    (144, 'POUCO URGENTE', 4, 2, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (144, 'POUCO URGENTE', 4, 3, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (144, 'POUCO URGENTE', 4, 4, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (144, 'POUCO URGENTE', 4, 5, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (144, 'POUCO URGENTE', 4, 6, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.');
INSERT INTO discriminadores (id_fluxograma, classificacao, prioridade, ordem, pergunta, explicacao) VALUES
    (145, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (145, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (145, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (145, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (145, 'MUITO URGENTE', 2, 2, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (145, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (145, 'MUITO URGENTE', 2, 4, 'HISTÓRIA DE OVERDOSE OU ENVENENAMENTO', 'ESTA INFORMAÇÃO PODE VIR DE OUTROS OU PODE SER DEDUZIDA NA PRESENÇA DE CAIXAS DE REMÉDIOS VAZIAS, ENTRE OUTRAS.'),
    (145, 'MUITO URGENTE', 2, 5, 'DOR PRECORDIAL OU CARDÍACA', 'DOR NO MEIO DO PEITO, GERALMENTE EM APERTO OU PESO, QUE PODE IRRADIAR PARA O BRAÇO ESQUERDO OU PESCOÇO. PODE-SE ASSOCIAR A SUDORESE, NÁUSEAS, SENSAÇÃO DE LIPOTIMIA E/OU DOR EPIGÁSTRICA.'),
    (145, 'MUITO URGENTE', 2, 6, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (145, 'MUITO URGENTE', 2, 7, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (145, 'URGENTE', 3, 1, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (145, 'URGENTE', 3, 2, 'PALPITAÇÃO ATUAL', 'SENSAÇÃO DE CORAÇÃO ACELERADO QUE AINDA ESTÁ PRESENTE NO MOMENTO DA CLASSIFICAÇÃO DE RISCO.'),
    (145, 'URGENTE', 3, 3, 'HISTÓRIA CARDÍACA IMPORTANTE', 'UMA ARRITMIA RECORRENTE AMEAÇADORA DA VIDA OU UMA CARDIOPATIA PREVIAMENTE CONHECIDA QUE PODE SE DETERIORAR RAPIDAMENTE.'),
    (145, 'URGENTE', 3, 4, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (145, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (145, 'POUCO URGENTE', 4, 1, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (146, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (146, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (146, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (146, 'MUITO URGENTE', 2, 1, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (146, 'MUITO URGENTE', 2, 2, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (146, 'MUITO URGENTE', 2, 3, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (146, 'MUITO URGENTE', 2, 4, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (146, 'MUITO URGENTE', 2, 5, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (146, 'URGENTE', 3, 1, 'AVULSÃO DENTÁRIA AGUDA', 'AVULSÃO DE UM DENTE INTEIRO NAS ÚLTIMAS 24H.'),
    (146, 'URGENTE', 3, 2, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (146, 'URGENTE', 3, 3, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (146, 'URGENTE', 3, 4, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (146, 'URGENTE', 3, 5, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (146, 'URGENTE', 3, 6, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (146, 'URGENTE', 3, 7, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (146, 'POUCO URGENTE', 4, 1, 'INCHAÇO NA FACE', 'INCHAÇO NA FACE QUE PODE SER LOCALIZADO OU DIFUSO.'),
    (146, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (146, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (146, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (146, 'POUCO URGENTE', 4, 5, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (147, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (147, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (147, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (147, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (147, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (147, 'MUITO URGENTE', 2, 2, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (147, 'MUITO URGENTE', 2, 3, 'COMPROMETIMENTO VASCULAR DISTAL', 'HAVERÁ ASSOCIAÇÃO DE PALIDEZ, ESFRIAMENTO, ALTERAÇÃO DA SENSIBILIDADE E/OU DOR COM OU SEM PULSO DISTAL À LESÃO.'),
    (147, 'MUITO URGENTE', 2, 4, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (147, 'MUITO URGENTE', 2, 5, 'PELE CRÍTICA', 'FRATURA OU DESLOCAMENTO PODE DEIXAR FRAGMENTOS OU PONTAS DE OSSO PRESSIONANDO A PELE DE TAL FORMA QUE PODE AMEAÇAR SUA VIABILIDADE. A PELE ESTARÁ PÁLIDA, SOB TENSÃO, EM RISCO.'),
    (147, 'MUITO URGENTE', 2, 6, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
