    (147, 'URGENTE', 3, 3, 'DEFORMIDADE GROSSEIRA', 'ISTO É SEMPRE SUBJETIVO. ANGULAÇÃO OU ROTAÇÃO GROSSEIRA OU ANORMAL É IMPLÍCITA.'),
    (147, 'URGENTE', 3, 4, 'FRATURA EXPOSTA', 'QUALQUER FERIDA AO REDOR DA FRATURA DEVE SER CONSIDERADA SUSPEITA. SE HOUVER ALGUMA POSSIBILIDADE DE COMUNICAÇÃO ENTRE A FERIDA E A FRATURA, ESTA DEVE SER CONSIDERADA EXPOSTA.'),
    (147, 'URGENTE', 3, 5, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
