    (147, 'URGENTE', 3, 7, 'DOR PLEURÍTICA', 'DOR LOCALIZADA NO TÓRAX QUE PIORA COM RESPIRAÇÃO, TOSSE OU ESPIRRO. DOR VENTILATÓRIO-DEPENDENTE.'),
    (147, 'URGENTE', 3, 8, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (147, 'POUCO URGENTE', 4, 1, 'DEFORMIDADE', 'ISTO É SEMPRE SUBJETIVO. INCLUI ANGULAÇÃO OU ROTAÇÃO ANORMAL.'),
    (147, 'POUCO URGENTE', 4, 2, 'INCHAÇO', 'QUALQUER AUMENTO ANORMAL NO TAMANHO.'),
