    (148, 'URGENTE', 3, 4, 'REDUÇÃO RECENTE DA ACUIDADE VISUAL', 'QUALQUER  REDUÇÃO DA ACUIDADE VISUAL OCORRIDA HÁ MENOS DE SETE DIAS.'),
    (148, 'URGENTE', 3, 5, 'AVULSÃO DENTÁRIA AGUDA', 'AVULSÃO DE UM DENTE INTEIRO NAS ÚLTIMAS 24H.'),
    (148, 'URGENTE', 3, 6, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
