    (148, 'POUCO URGENTE', 4, 10, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (149, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (149, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (149, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (149, 'EMERGÊNCIA', 1, 4, 'LESÃO OCULAR QUÍMICA AGUDA', 'QUALQUER SUBSTÂNCIA QUE RESPINGA OU CAI NOS OLHOS NAS ÚLTIMAS 12 HORAS E CAUSA DOR, QUEIMAÇÃO, REDUÇÃO DA VISÃO OU QUALQUER OUTRO SINTOMA.'),
    (149, 'MUITO URGENTE', 2, 1, 'TRAUMA OCULAR PENETRANTE', 'EVENTO TRAUMÁTICO FÍSICO RECENTE COM PERFURAÇÃO DO GLOBO OCULAR.'),
    (149, 'MUITO URGENTE', 2, 2, 'PERDA TOTAL DA VISÃO AGUDA', 'PERDA DA VISÃO EM UM OU AMBOS OS OLHOS NAS ÚLTIMAS 24H E QUE NÃO VOLTOU AO NORMAL.'),
    (149, 'MUITO URGENTE', 2, 3, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
