    (149, 'MUITO URGENTE', 2, 5, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (149, 'MUITO URGENTE', 2, 6, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (149, 'MUITO URGENTE', 2, 7, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (149, 'MUITO URGENTE', 2, 8, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (149, 'URGENTE', 3, 1, 'REDUÇÃO RECENTE DA ACUIDADE VISUAL', 'QUALQUER  REDUÇÃO DA ACUIDADE VISUAL OCORRIDA HÁ MENOS DE SETE DIAS.'),
