    (151, 'MUITO URGENTE', 2, 2, 'IMUNOSSUPRESSÃO CONHECIDA OU PROVÁVEL', 'QUALQUER PACIENTE EM USO DE DROGAS IMUNOSSUPRESSORAS (INCLUINDO USO PROLONGADO DE CORTICOIDE) OU COM DOENÇA QUE CAUSE IMUNOSSUPRESSÃO.'),
    (151, 'MUITO URGENTE', 2, 3, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (151, 'MUITO URGENTE', 2, 4, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (151, 'MUITO URGENTE', 2, 5, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (151, 'MUITO URGENTE', 2, 6, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (151, 'MUITO URGENTE', 2, 7, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (151, 'URGENTE', 3, 1, 'HEMATÚRIA FRANCA', 'COLORAÇÃO VERMELHA DA URINA CAUSADA POR SANGUE.'),
    (151, 'URGENTE', 3, 2, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (151, 'URGENTE', 3, 3, 'RETENÇÃO URINÁRIA', 'IMPOSSIBILIDADE DE ELIMINAR URINA PELA URETRA ASSOCIADA A BEXIGOMA. É UMA CONDIÇÃO DE MUITA DOR, EXCETO SE HOUVER ALTERAÇÃO DO SENSÓRIO.'),
    (151, 'URGENTE', 3, 4, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (151, 'URGENTE', 3, 5, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (151, 'URGENTE', 3, 6, 'CÓLICAS', 'DORES INTERMITENTES (EM ONDAS) QUE TENDEM A MELHORAR OU PIORAR A CADA 20 MINUTOS.'),
    (151, 'URGENTE', 3, 7, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (151, 'POUCO URGENTE', 4, 1, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (151, 'POUCO URGENTE', 4, 2, 'DISÚRIA', 'DOR E/OU DIFICULDADE EM URINAR. A DOR É TIPICAMENTE DESCRITA COMO FINCADA OU QUEIMAÇÃO.'),
    (151, 'POUCO URGENTE', 4, 3, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (151, 'POUCO URGENTE', 4, 4, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (151, 'POUCO URGENTE', 4, 5, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (151, 'POUCO URGENTE', 4, 6, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (151, 'POUCO URGENTE', 4, 7, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (152, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (152, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (152, 'EMERGÊNCIA', 1, 3, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (152, 'EMERGÊNCIA', 1, 4, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (152, 'EMERGÊNCIA', 1, 5, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (152, 'EMERGÊNCIA', 1, 6, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (152, 'MUITO URGENTE', 2, 1, 'NOVO PULSO ANORMAL', 'BRADICARDIA (FREQUÊNCIA DE PULSO ABAIXO DE 60 BPM EM ADULTOS), TAQUICARDIA (FREQUÊNCIA DE PULSO ACIMA DE 100 BPM EM ADULTOS) OU RITMO IRREGULAR. NA CRIANÇA DEVE-SE DEFINIR BRADICARDIA E TAQUICARDIA CONFORME A IDADE. DEVE-SE CONSIDERAR ALTERAÇÃO DE FREQUÊNCIA DE PULSO E/OU RITMO QUE ESTÁ OCORRENDO NESTE EPISÓDIO.'),
    (152, 'MUITO URGENTE', 2, 2, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (152, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (152, 'MUITO URGENTE', 2, 4, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (152, 'MUITO URGENTE', 2, 5, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (152, 'MUITO URGENTE', 2, 6, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (152, 'MUITO URGENTE', 2, 7, 'NEONATO QUENTE', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (152, 'MUITO URGENTE', 2, 8, 'BEBÊ QUENTE', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C OU MAIS.'),
    (152, 'MUITO URGENTE', 2, 9, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (152, 'MUITO URGENTE', 2, 10, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (152, 'MUITO URGENTE', 2, 11, 'SEPSE POSSÍVEL', 'EM ADULTO CONSIDERAR: ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA DESDE CONFUSÃO AO ESTUPOR OU COMA (ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO) OU FREQUÊNCIA RESPIRATÓRIA MAIOR QUE 22IRPM OU PRESSÃO ARTERIAL SISTÓLICA MENOR QUE 100 MMHG. EM BEBÊ E CRIANÇA CONSIDERAR: PULSO ANORMAL POR FAIXA ETÁRIA SE TEMPERATURA TIMPÂNICA FOR MENOR QUE 38,5°C OU ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA, POUCA INTERAÇÃO COM OS FAMILIARES) OU PERFUSÃO CAPILAR MAIOR QUE 2 SEGUNDOS. EM NEONATOS CONSIDERAR: ALTERAÇÃO DO PADRÃO DE ATIVIDADE (IRRITABILIDADE, CHORO INCONSOLÁVEL, SONOLÊNCIA) OU PREENCHIMENTO CAPILAR CENTRAL MAIOR QUE 2 SEGUNDOS (REALIZADO NO TÓRAX).'),
    (152, 'MUITO URGENTE', 2, 12, 'HIPOTERMIA', 'SE A PELE SE APRESENTA FRIA DIZ-SE QUE O PACIENTE ESTÁ CLINICAMENTE HIPOTÉRMICO. A TEMPERATURA DEVE SER AFERIDA LOGO QUE POSSÍVEL. TEMPERATURA MENOR QUE 35°C DEFINE HIPOTERMIA.'),
    (152, 'MUITO URGENTE', 2, 13, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (152, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (152, 'URGENTE', 3, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (152, 'URGENTE', 3, 3, 'DEFORMIDADE GROSSEIRA', 'ISTO É SEMPRE SUBJETIVO. ANGULAÇÃO OU ROTAÇÃO GROSSEIRA OU ANORMAL É IMPLÍCITA.'),
    (152, 'URGENTE', 3, 4, 'FRATURA EXPOSTA', 'QUALQUER FERIDA AO REDOR DA FRATURA DEVE SER CONSIDERADA SUSPEITA. SE HOUVER ALGUMA POSSIBILIDADE DE COMUNICAÇÃO ENTRE A FERIDA E A FRATURA, ESTA DEVE SER CONSIDERADA EXPOSTA.'),
    (152, 'URGENTE', 3, 5, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (152, 'URGENTE', 3, 6, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (152, 'URGENTE', 3, 7, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (152, 'URGENTE', 3, 8, 'NEONATO FEBRIL', 'SE A PELE DO RECÉM-NASCIDO (COM IDADE DE 28 DIAS OU MENOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (152, 'URGENTE', 3, 9, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.');
INSERT INTO discriminadores (id_fluxograma, classificacao, prioridade, ordem, pergunta, explicacao) VALUES
    (152, 'URGENTE', 3, 10, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (152, 'URGENTE', 3, 11, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (152, 'POUCO URGENTE', 4, 1, 'BEBÊ FEBRIL', 'SE A PELE DO BEBÊ (COM IDADE MAIOR DE 28 DIAS ATÉ UM ANO) ESTIVER RE­LATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (152, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (152, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (152, 'POUCO URGENTE', 4, 4, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (152, 'POUCO URGENTE', 4, 5, 'DEFORMIDADE', 'ISTO É SEMPRE SUBJETIVO. INCLUI ANGULAÇÃO OU ROTAÇÃO ANORMAL.'),
    (152, 'POUCO URGENTE', 4, 6, 'INCHAÇO', 'QUALQUER AUMENTO ANORMAL NO TAMANHO.'),
    (152, 'POUCO URGENTE', 4, 7, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (153, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (153, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (153, 'EMERGÊNCIA', 1, 3, 'ESTRIDOR', 'RUÍDO INSPIRATÓRIO, EXPIRATÓRIO OU AMBOS, MELHOR ESCUTADO AO SE RESPIRAR DE BOCA ABERTA.'),
    (153, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (153, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (153, 'MUITO URGENTE', 2, 1, 'EDEMA FACIAL', 'INCHAÇO DIFUSO NA FACE GERALMENTE ENVOLVENDO OS LÁBIOS.'),
    (153, 'MUITO URGENTE', 2, 2, 'LESÃO POR INALAÇÃO', 'HISTÓRIA DE CONFINAMENTO EM ESPAÇO COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE ASPIRAÇÃO DE FUMAÇA. FULIGEM EM TORNO DA BOCA E NARIZ, ALÉM DE ROUQUIDÃO, ESTARÁ PRESENTE. HISTÓRIA É TAMBÉM A FORMA MAIS SEGURA DE SE DIAGNOSTICAR INALAÇÃO DE AGENTES QUÍMICOS - PODE NÃO HAVER ALGUM OUTRO SINAL.'),
    (153, 'MUITO URGENTE', 2, 3, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (153, 'MUITO URGENTE', 2, 4, 'SATURAÇÃO DE O2 MUITO BAIXA', 'SATURAÇÃO DE OXIGÊNIO ABAIXO DE 95% EM TERAPIA COM O2 OU ABAIXO DE 92% EM AR AMBIENTE.'),
    (153, 'MUITO URGENTE', 2, 5, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (153, 'MUITO URGENTE', 2, 6, 'MORTALIDADE QUÍMICA ALTA', 'MORTALIDADE É O POTENCIAL DE UMA SUBSTÂNCIA QUÍMICA CAUSAR DANO. INTERCONSULTA EM UM CENTRO DE INTOXICAÇÕES PODE SER NECESSÁRIA PARA SE ESTABELECER O RISCO DE LESÃO OU MORTE. NA DÚVIDA, CONSIDERE ALTO O RISCO.'),
    (153, 'MUITO URGENTE', 2, 7, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (153, 'MUITO URGENTE', 2, 8, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (153, 'URGENTE', 3, 1, 'SATURAÇÃO DE O2 BAIXA', 'SATURAÇÃO DE OXIGÊNIO MENOR QUE 95% EM AR AMBIENTE.'),
    (153, 'URGENTE', 3, 2, 'EXPOSIÇÃO À FUMAÇA', 'HISTÓRIA DE CONFINAMENTO EM LUGAR COM FUMAÇA É O INDICADOR MAIS CONFIÁVEL DE EXPOSIÇÃO À FUMAÇA. PODE HAVER FULIGEM EM TORNO DA BOCA E NARIZ.'),
    (153, 'URGENTE', 3, 3, 'QUEIMADURA ELÉTRICA', 'QUALQUER QUEIMADURA CAUSADA OU POSSIVELMENTE CAUSADA POR CORRENTE ELÉTRICA. ISTO INCLUI CORRENTES ALTERNADAS E CONTÍNUAS, TANTO DE FONTES NATURAIS COMO ARTIFICIAIS.'),
    (153, 'URGENTE', 3, 4, 'MORTALIDADE QUÍMICA MODERADA', 'MORTALIDADE É O POTENCIAL DE UMA SUBSTÂNCIA QUÍMICA CAUSAR DANO. INTERCONSULTA EM UM CENTRO DE INTOXICAÇÕES PODE SER NECESSÁRIA PARA SE ESTABELECER O RISCO DE LESÃO OU MORTE. NA DÚVIDA, CONSIDERE ESTE DISCRIMINADOR.'),
    (153, 'URGENTE', 3, 5, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (153, 'URGENTE', 3, 6, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (153, 'POUCO URGENTE', 4, 1, 'INFLAMAÇÃO LOCAL', 'IMPLICA DOR, INCHAÇO E VERMELHIDÃO, RESTRITA A UMA ÁREA DEFINIDA.'),
    (153, 'POUCO URGENTE', 4, 2, 'INFECÇÃO LOCAL', 'MANIFESTA-SE GERALMENTE COMO INFLAMAÇÃO (DOR, INCHAÇO E VERMELHIDÃO) RESTRITA A UMA ÁREA DEFINIDA, COM OU SEM COLEÇÃO DE PUS.'),
    (153, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (153, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (154, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (154, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (154, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (154, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (154, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (154, 'MUITO URGENTE', 2, 1, 'SANGRAMENTO VAGINAL INTENSO', 'ANGRAMENTO VAGINAL É MUITO DIFÍCIL DE QUANTIFICAÇÃO. EVIDÊNCIAS DE GRANDES PERDAS DE SANGUE PELA VAGINA OU FLUXO CONSTANTE PREENCHEM ESTE CRITÉRIO. GRANDES COÁGULOS PODEM SER OBSERVADOS. O USO DE GRANDE NÚMERO DE ABSORVENTES HIGIÊNICOS SUGERE PERDA INTENSA.'),
    (154, 'MUITO URGENTE', 2, 2, 'SANGRAMENTO VAGINAL COM 20 SEMANAS DE GRAVIDEZ OU MAIS', 'QUALQUER PERDA DE SANGUE PELA VAGINA EM MULHER SABIDAMENTE COM 20 SEMANAS DE GRAVIDEZ OU MAIS.'),
    (154, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (154, 'MUITO URGENTE', 2, 4, 'CRIANÇA MUITO QUENTE', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER MUITO QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (154, 'MUITO URGENTE', 2, 5, 'ADULTO MUITO QUENTE', 'SE A PELE ESTIVER MUITO QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE MUITO QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL, CORRESPONDE À TEMPERATURA DE 41 °C OU MAIS.'),
    (154, 'MUITO URGENTE', 2, 6, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (154, 'URGENTE', 3, 1, 'TRAUMA VAGINAL', 'QUALQUER HISTÓRIA OU OUTRA EVIDÊNCIA DE TRAUMA NA VAGINA.'),
    (154, 'URGENTE', 3, 2, 'GRAVIDEZ POSSÍVEL', 'QUALQUER MULHER CUJA MENSTRUAÇÃO NORMAL NÃO OCORREU ESTÁ POSSIVELMENTE GRÁVIDA. ALÉM DISSO, PARA QUALQUER MULHER EM IDADE FÉRTIL COM VIDA SEXUAL ATIVA SEM PROTEÇÃO DEVERÁ SER CONSIDERADA A POSSIBILIDADE DE GRAVIDEZ.'),
    (154, 'URGENTE', 3, 3, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (154, 'URGENTE', 3, 4, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (154, 'URGENTE', 3, 5, 'DOR ABDOMINAL', 'RELATO DE QUALQUER DOR SENTIDA NO ABDOME. SE IRRADIADA PARA O DORSO PODE INDICAR DISSECÇÃO DE AORTA; SE ASSOCIADA A SANGRAMENTO VAGINAL, PODE SUGERIR GRAVIDEZ ECTÓPICA OU ABORTAMENTO.'),
    (154, 'URGENTE', 3, 6, 'DOR IRRADIADA PARA O OMBRO', 'DOR SENTIDA NA PONTA DO OMBRO. GERALMENTE INDICA IRRITAÇÃO DIAFRAGMÁTICA.'),
    (154, 'URGENTE', 3, 7, 'CRIANÇA QUENTE', 'SE A PELE DA CRIANÇA (MAIOR DE 1 ANO ATÉ 14 ANOS) ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (154, 'URGENTE', 3, 8, 'ADULTO QUENTE', 'SE A PELE ESTIVER QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE QUENTE. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 38,5°C ATÉ 40,9°C.'),
    (154, 'URGENTE', 3, 9, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (154, 'POUCO URGENTE', 4, 1, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (154, 'POUCO URGENTE', 4, 2, 'CRIANÇA FEBRIL', 'SE A PELE DA CRIANÇA (COM IDADE ENTRE UM E 14 ANOS) ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER CLINICAMENTE QUE A CRIANÇA ESTÁ FEBRIL. A TEMPERATURA DEVE SER MEDIDA ASSIM QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (154, 'POUCO URGENTE', 4, 3, 'ADULTO FEBRIL', 'SE A PELE ESTIVER RELATIVAMENTE QUENTE, PODE-SE DIZER QUE O PACIENTE ESTÁ CLINICAMENTE FEBRIL. A TEMPERATURA DEVE SER MEDIDA LOGO QUE POSSÍVEL. CORRESPONDE À TEMPERATURA DE 37,5°C ATÉ 38,4°C.'),
    (154, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (155, 'EMERGÊNCIA', 1, 1, 'OBSTRUÇÃO DE VIAS AÉREAS', 'VIA AÉREA PODE ESTAR OBSTRUÍDA POR NÃO SE MANTER PÉRVIA OU POR PERDER REFLEXOS PROTETORES QUE EVITAM ASPIRAÇÃO. A FALÊNCIA EM SE MANTER VIA AÉREA PÉRVIA RESULTARÁ EM OBSTRUÇÃO TOTAL INTERMITENTE OU OBSTRUÇÃO PARCIAL MANIFESTADA POR RONCOS OU GORGOLEJOS DURANTE A RESPIRAÇÃO.'),
    (155, 'EMERGÊNCIA', 1, 2, 'RESPIRAÇÃO INADEQUADA', 'PACIENTE QUE NÃO CONSEGUE RESPIRAR O SUFICIENTE PARA MANTER OXIGENAÇÃO ADEQUADA. PODE HAVER AUMENTO DO TRABALHO RESPIRATÓRIO, SINAS DE RESPIRAÇÃO INADEQUADA OU EXAUSTÃO.'),
    (155, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (155, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (155, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (155, 'EMERGÊNCIA', 1, 6, 'CONVULSIONANDO', 'PACIENTE QUE ESTÁ APRESENTANDO MOVIMENTOS TÔNICOS OU CLÔNICOS DE UMA CRISE CONVULSIVA TIPO GRANDE MAL OU APRESENTANDO CONVULSÃO PARCIAL.'),
    (155, 'EMERGÊNCIA', 1, 7, 'HIPOGLICEMIA', 'GLICEMIA MENOR QUE 55 MG/DL.'),
    (155, 'MUITO URGENTE', 2, 1, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (155, 'MUITO URGENTE', 2, 2, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (155, 'MUITO URGENTE', 2, 3, 'NOVO DÉFICIT NEUROLÓGICO HÁ MENOS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA QUE OCORREU NAS ÚLTIMAS 24H: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL.'),
    (155, 'MUITO URGENTE', 2, 4, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (155, 'MUITO URGENTE', 2, 5, 'HIPERGLICEMIA COM CETOSE', 'GLICEMIA MAIOR QUE 200 MG/DL COM CETONEMIA, CETONÚRIA OU SINAIS DE ACIDOSE (RESPIRAÇÃO DE KUSSMAUL - PROFUNDA E/OU HÁLITO CETÔNICO).'),
    (155, 'MUITO URGENTE', 2, 6, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (155, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (155, 'URGENTE', 3, 2, 'NOVO DÉFICIT NEUROLÓGICO HÁ MAIS DE 24 HORAS', 'QUALQUER NOVA PERDA DE FUNÇÃO NEUROLÓGICA: ALTERAÇÃO OU PERDA DE SENSIBILIDADE, FRAQUEZA DE MEMBROS (TRANSITÓRIA OU PERMANENTE), RETENÇÃO URINÁRIA OU ALTERAÇÃO DA FUNÇÃO INTESTINAL HÁ MAIS DE 24H.'),
    (155, 'URGENTE', 3, 3, 'VÔMITOS PERSISTENTES', 'VÔMITOS CONTÍNUOS OU QUE OCORREM SEM ALÍVIO ENTRE OS EPISÓDIOS.'),
    (155, 'URGENTE', 3, 4, 'HISTÓRIA DE INCONSCIÊNCIA', 'DEVE HAVER UMA TESTEMUNHA CONFIÁVEL PARA RELATAR SE O PACIENTE PERDEU A CONSCIÊNCIA E POR QUANTO TEMPO. CASO CONTRÁRIO, SE O PACIENTE NÃO SE LEMBRA DO INCIDENTE, DEVE-SE PRESUMIR QUE ESTEVE INCONSCIENTE.'),
    (155, 'URGENTE', 3, 5, 'HIPERGLICEMIA', 'GLICEMIA MAIOR QUE 300 MG/DL.'),
    (155, 'URGENTE', 3, 6, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (155, 'URGENTE', 3, 7, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (155, 'URGENTE', 3, 8, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (155, 'POUCO URGENTE', 4, 1, 'HEMATOMA DE COURO CABELUDO', 'ÁREA DO COURO CABELUDO CONTUSA, MACHUCADA E ELEVADA. CONTUSÃO NA TESTA ABAIXO DA LINHA DO CABELO É DITA FRONTAL.'),
    (155, 'POUCO URGENTE', 4, 2, 'VÔMITO', 'QUALQUER ÊMESE PREENCHE ESTE CRITÉRIO.'),
    (155, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (155, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
