    (156, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (156, 'MUITO URGENTE', 2, 2, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
