    (157, 'EMERGÊNCIA', 1, 3, 'HEMORRAGIA EXSANGUINANTE', 'HEMORRAGIA QUE ESTÁ OCORRENDO DE TAL FORMA QUE OCORRERÁ A MORTE SE NÃO FOR CONTIDA.'),
    (157, 'EMERGÊNCIA', 1, 4, 'CHOQUE', 'CHOQUE É DEFINIDO COMO OXIGENAÇÃO INADEQUADA DOS TECIDOS QUE RESULTA EM MÁ-PERFUSÃO TECIDUAL. SÃO SINAIS CLÁSSICOS: SUDORESE, PALIDEZ, TAQUICARDIA, HIPOTENSÃO E DIMINUIÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (157, 'EMERGÊNCIA', 1, 5, 'CRIANÇA NÃO REATIVA', 'CRIANÇA QUE NÃO RESPONDE AO COMANDO VERBAL OU AO ESTÍMULO DOLOROSO.'),
    (157, 'MUITO URGENTE', 2, 1, 'DISPNEIA AGUDA', 'FÔLEGO CURTO OU FALTA DE AR SÚBITA OU REPENTINA PIORA DE FALTA DE AR CRÔNICA.'),
    (157, 'MUITO URGENTE', 2, 2, 'HEMORRAGIA MAIOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR FORTEMENTE OU ENCHARCA RAPIDAMENTE O CURATIVO.'),
    (157, 'MUITO URGENTE', 2, 3, 'ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA', 'PACIENTE NÃO TOTALMENTE ALERTA, COM ALTERAÇÃO DA ESCALA DE COMA DE GLASGOW EM RELAÇÃO AO ESTADO PRÉVIO. RESPONDE APENAS À VOZ OU À DOR OU ESTÁ IRRESPONSIVO. EM CASO DE DÚVIDA, PRESUMIR ALTERAÇÃO DO NÍVEL DE CONSCIÊNCIA.'),
    (157, 'MUITO URGENTE', 2, 4, 'EVISCERAÇÃO', 'HERNIAÇÃO OU FRANCA EXTERIORIZAÇÃO DE ÓRGÃOS INTERNOS.'),
    (157, 'MUITO URGENTE', 2, 5, 'MECANISMO DE TRAUMA SIGNIFICATIVO', 'TRAUMA PENETRANTE (FACADA OU TIRO) E TRAUMA COM ALTA TRANSFERÊNCIA DE ENERGIA COMO QUEDA DE ALTURA E ACIDENTES EM VIAS DE TRÂNSITO RÁPIDO (VELOCIDADE ACIMA DE 60 KM/H) SÃO SIGNIFICATIVOS, PRINCIPALMENTE SE HOUVE EJEÇÃO DO VEÍCULO, MORTES DE OUTRAS VÍTIMAS OU GRANDE DEFORMAÇÃO DO VEÍCULO.'),
    (157, 'MUITO URGENTE', 2, 6, 'DOR INTENSA', 'DOR INTOLERÁVEL, GERALMENTE DESCRITA COMO JAMAIS SENTIDA. VER RÉGUA DA DOR.'),
    (157, 'URGENTE', 3, 1, 'HEMORRAGIA MENOR INCONTROLÁVEL', 'HEMORRAGIA QUE NÃO É RAPIDAMENTE CONTROLADA POR COMPRESSÃO DIRETA E SUSTENTADA. O SANGUE CONTINUA A FLUIR LEVEMENTE OU A ESCORRER.'),
    (157, 'URGENTE', 3, 2, 'HISTÓRIA HEMATOLÓGICA OU METABÓLICA SIGNIFICATIVA', 'PACIENTE COM CONDIÇÃO HEMATOLÓGICA SIGNIFICATIVA OU DESORDEM METABÓLICA CONGÊNITA COM CONHECIDA POSSIBILIDADE DE DETERIORAÇÃO RÁPIDA.'),
    (157, 'URGENTE', 3, 3, 'HISTÓRIA DISCORDANTE', 'QUANDO A HISTÓRIA FORNECIDA NÃO EXPLICA OS ACHADOS FÍSICOS. PODE SER UM MARCADOR DE LESÃO NÃO ACIDENTAL EM CRIANÇAS OU ADULTOS VULNERÁVEIS, PODENDO SER SENTINELA DE ABUSO E MAUS TRATOS.'),
    (157, 'URGENTE', 3, 4, 'DOR PLEURÍTICA', 'DOR LOCALIZADA NO TÓRAX QUE PIORA COM RESPIRAÇÃO, TOSSE OU ESPIRRO. DOR VENTILATÓRIO-DEPENDENTE.'),
    (157, 'URGENTE', 3, 5, 'DOR MODERADA', 'DOR INTENSA, MAS SUPORTÁVEL. VER RÉGUA DA DOR.'),
    (157, 'POUCO URGENTE', 4, 1, 'INFLAMAÇÃO LOCAL', 'IMPLICA DOR, INCHAÇO E VERMELHIDÃO, RESTRITA A UMA ÁREA DEFINIDA.'),
    (157, 'POUCO URGENTE', 4, 2, 'INFECÇÃO LOCAL', 'MANIFESTA-SE GERALMENTE COMO INFLAMAÇÃO (DOR, INCHAÇO E VERMELHIDÃO) RESTRITA A UMA ÁREA DEFINIDA, COM OU SEM COLEÇÃO DE PUS.'),
    (157, 'POUCO URGENTE', 4, 3, 'DOR LEVE RECENTE', 'QUALQUER DOR QUE TENHA OCORRIDO HÁ MENOS DE SETE DIAS. VEJA RÉGUA DA DOR.'),
    (157, 'POUCO URGENTE', 4, 4, 'EVENTO RECENTE', 'PROBLEMA QUE SURGIU HÁ MENOS DE SETE DIAS.'),
    (158, 'POUCO URGENTE', 4, 1, 'ANDA', 'EM ACIDENTE ENVOLVENDO MÚLTIPLAS VÍTIMAS, AO SER ACIONADO O PLANO DE CATÁSTROFE, QUALQUER PACIENTE QUE POSSA CAMINHAR, INDEPENDENTEMENTE DE SEU FERIMENTO, PREENCHE ESTE CRITÉRIO, SENDO PRIORIZADO COMO PADRÃO (VERDE).'),
    (158, 'EMERGÊNCIA', 1, 1, 'FREQUÊNCIA RESPIRATÓRIA ANORMAL (< 10 OU > 29 IPM)', 'EM SITUAÇÕES DE MÚLTIPLAS VÍTIMAS, CONSIDERA-SE FREQUÊNCIA RESPIRATÓRIA ANORMAL QUANDO ELA ESTÁ MUITO ALTA (>29) OU MUITO BAIXA (<10). É PRIORIZADA COMO VERMELHA.'),
    (158, 'EMERGÊNCIA', 1, 2, 'PERFUSÃO CAPILAR ANORMAL (> 2 SEG)', 'TEMPO DE PERFUSÃO CAPILAR É O TEMPO DE PREENCHIMENTO DO LEITO UNGUEAL APÓS SER APLICADA PRESSÃO POR 5 SEGUNDOS. O VALOR NORMAL É MENOR QUE 2 SEG, MAS ESTE SINAL É POUCO ÚTIL EM CASO DE HIPOTERMIA. EM SITUAÇÕES DE MÚLTIPLAS VÍTIMAS, QUANDO A PERFUSÃO CAPILAR ESTÁ PROLONGADA (MAIOR QUE 2 SEGUNDOS), O PACIENTE É PRIORIZADO COMO VERMELHO.'),
    (158, 'EMERGÊNCIA', 1, 3, 'FREQUÊNCIA DE PULSO ANORMAL (> 120 BPM)', 'SE A PERFUSÃO CAPILAR NÃO PUDER SER MEDIDA EM SITUAÇÕES DE MÚLTIPLAS VÍTIMAS, A FREQUÊNCA DE PULSO MAIOR QUE 120 POR MINUTO É PRIORIZADA COMO VERMELHA.'),
    (158, 'EMERGÊNCIA', 1, 4, 'RESPIRA APÓS ABERTURA DE VIAS AÉREAS', 'EM SITUAÇÕES DE MÚLTIPLAS VÍTIMAS, DEVE SER AVALIADA A PRESENÇA DE RESPIRAÇÃO APÓS ABERTURA DE VIA AÉREA. A AUSÊNCIA DE RESPIRAÇÃO POR 10 SEGUNDOS APÓS MANOBRA DE ABERTURA DA VIA AÉREA IMPLICA EM DECLARAÇÃO DE ÓBITO (UMA COMPETÊNCIA MÉDICA), A NÃO SER QUE HAJA RECURSO PARA RESSUCITAÇÃO CARDIOPULMONAR SEM PREJUÍZO AO ATENDIMENTO DE OUTRAS VÍTIMAS CLASSIFICADAS COMO VERMELHO.'),
    (159, 'EMERGÊNCIA', 1, 1, 'TRTS 1 A 10', 'A PONTUAÇÃO DO TRTS É FEITA CONSIDERANDO A FREQUÊNCIA RESPIRATÓRIA (0-4), PRESSÃO ARTERIAL SISTÓLICA (0-4) E ESCALA DE COMA DE GLASGOW (0-4) PARA SE OBTER PONTUAÇÃO FINAL DE 0 A 12.'),
    (159, 'URGENTE', 3, 1, 'TRTS = 11', 'A PONTUAÇÃO DO TRTS É FEITA CONSIDERANDO A FREQUÊNCIA RESPIRATÓRIA (0-4), PRESSÃO ARTERIAL SISTÓLICA (0-4) E ESCALA DE COMA DE GLASGOW (0-4) PARA SE OBTER PONTUAÇÃO FINAL DE 0 A 12.'),
    (159, 'POUCO URGENTE', 4, 1, 'TRTS = 12', 'A PONTUAÇÃO DO TRTS É FEITA CONSIDERANDO A FREQUÊNCIA RESPIRATÓRIA (0-4), PRESSÃO ARTERIAL SISTÓLICA (0-4) E ESCALA DE COMA DE GLASGOW (0-4) PARA SE OBTER PONTUAÇÃO FINAL DE 0 A 12.');
